head.script:
//
// Initialize user preferences
!function() {
  var root = document.documentElement;
  var theme = localStorage.getItem("theme") || (window.matchMedia("(prefers-color-scheme: dark)").matches ? "dark" : "light");
  var lang = localStorage.getItem("lang");
  var variant = localStorage.getItem("variant");

  if (!lang) {
    var userLang = (navigator.language || navigator.userLanguage).toLowerCase();
    lang = userLang.includes("zh") ? "zh" : "en";
    variant = userLang.match(/(tw|hk|mo|hant)/) ? "trad" : "simp";
    localStorage.setItem("lang", lang);
    localStorage.setItem("variant", variant);
  }

  root.setAttribute("data-theme", theme);
  root.setAttribute("data-lang", lang);
  root.setAttribute("data-variant", variant || "simp");
}();
//

head.b:skin:
/* Light theme — Anthropic-style warm editorial palette: ivory
   paper, near-black ink, a warm hairline. The brand accent stays
   green, but retuned to an earthier olive-sage so it sits in this
   warm system the way Anthropic's coral does. --persimmon is set to
   Anthropic's exact coral (#d97757) as the secondary warm tone. */
:root {
  /* Theme the native UI too — scrollbars, form controls, the canvas —
     so they match light/dark instead of the dark-mode scrollbar
     staying light. (The comment iframe keeps its own forced light
     scheme for the re-tint filter, set locally.) */
  color-scheme: light;
  --bg-color: #faf9f4;
  --text-color: #20201d;
  --meta-color: #6b6960;
  /* Accent darkened slightly so green text clears WCAG AA contrast on
     the warm paper (e.g. the active nav link flagged by PageSpeed). */
  --accent-color: #55703e;
  /* Derived from the accent so it tracks any future hue change
     instead of drifting out of sync as a hand-coded rgba would. */
  --accent-bg: color-mix(in srgb, var(--accent-color) 10%, transparent);
  --persimmon: #d97757;
  --btn-bg: rgba(40, 36, 28, 0.04);
  --border-color: #e8e3d7;
  --icon-color: #6f6d64;
  --container-width: 700px;
  /* ── Frosted-glass material ───────────────────────────────────────
     Shared surface for the floating chrome, tinted toward the warm
     paper bg rather than cold white so it sits naturally on the page.
     Two tiers: --glass-bg is airy (icon buttons, hint), --glass-panel
     is more opaque for surfaces that carry text (speech bubble, menu)
     so the words stay crisp. --glass-edge fakes a soft convex rim in
     place of a border; --glass-drop is the faint shadow beneath. */
  --glass-bg: linear-gradient(180deg, rgba(252, 250, 244, 0.46), rgba(249, 247, 239, 0.30));
  --glass-panel: linear-gradient(180deg, rgba(253, 251, 246, 0.62), rgba(250, 248, 241, 0.52));
  /* Stronger frost: a wide blur + extra saturation so the glass reads
     clearly as glass — the backdrop visibly diffuses through the very
     translucent panels above. Every frosted surface (hint, bubble +
     tail, gear, settings menu, re-open handle) draws from these
     variables, so they all share this material. Text on the panels
     stays legible because its content is high-contrast. */
  --glass-blur: blur(22px) saturate(185%);
  --glass-fill: rgba(252, 250, 245, 0.62);
  --glass-edge: inset 0 1px 0 rgba(255, 255, 255, 0.8), inset 0 0 0 1px rgba(255, 255, 255, 0.34);
  --glass-drop: 0 5px 16px rgba(40, 36, 28, 0.10);
  --glass-drop-pop: 0 14px 32px rgba(40, 36, 28, 0.16);
  /* Sage hover wash, laid over the glass as an inset shadow layer so it
     fades smoothly (gradient→gradient can't be transitioned). */
  --glass-tint: color-mix(in srgb, var(--accent-color) 18%, transparent);
  /* Motion system — Apple/Anthropic-flavoured easing. --ease is a
     gentle in-out for reversible states (colour changes); --ease-out
     is a settled decelerating curve for things that appear or travel
     (fades, reveals, the hint pill). --ease-spring adds a small
     overshoot (Apple's "back" feel) and is used ONLY on the transform
     of hover lifts/presses, so a button springs into place while its
     colour still eases linearly — never applied to opacity, width or
     collapse transitions, which would visibly bounce. */
  --ease: cubic-bezier(0.4, 0, 0.2, 1);
  --ease-out: cubic-bezier(0.22, 1, 0.36, 1);
  --ease-spring: cubic-bezier(0.34, 1.56, 0.64, 1);
}

/* Dark theme — warm charcoal (not cool grey) to match Anthropic's
   dark surfaces; the accent lifts to a warm light sage. */
[data-theme="dark"] {
  color-scheme: dark;
  --bg-color: #1a1915;
  --text-color: #e4e1d8;
  --meta-color: #918e83;
  --accent-color: #a6c187;
  --accent-bg: color-mix(in srgb, var(--accent-color) 10%, transparent);
  --btn-bg: rgba(255, 255, 255, 0.05);
  --border-color: #2d2b25;
  --icon-color: #918e83;
  /* Dark glass — modern frosted-pane look: a flat, more translucent
     fill so the backdrop blur shows through (rather than a heavy slab),
     and a large, soft, diffuse shadow. Tone is a near-neutral warm
     graphite — light enough above the page that its edges read by
     luminance contrast, so it needs NO drawn rim (a full white inset
     ring shows up as a hard white frame on dark); just a faint top
     sheen where light would catch. */
  --glass-bg: linear-gradient(180deg, rgba(58, 57, 53, 0.34), rgba(48, 47, 43, 0.28));
  --glass-panel: linear-gradient(180deg, rgba(52, 51, 47, 0.58), rgba(44, 43, 40, 0.50));
  --glass-fill: rgba(52, 51, 47, 0.56);
  --glass-edge: inset 0 1px 0 rgba(255, 255, 255, 0.06);
  --glass-drop: 0 8px 30px rgba(0, 0, 0, 0.40);
  --glass-drop-pop: 0 20px 50px rgba(0, 0, 0, 0.50);
  --glass-tint: color-mix(in srgb, var(--accent-color) 24%, transparent);
}

/* Fallback when backdrop-filter is unavailable (older engines, some
   embedded webviews): with no blur to lift text off whatever sits
   behind, the very translucent glass would be hard to read. So make
   the surfaces near-opaque instead — same warm tone, just solid. All
   frosted elements read from these variables, so this covers every one
   at once. */
@supports not ((-webkit-backdrop-filter: blur(1px)) or (backdrop-filter: blur(1px))) {
  :root {
    --glass-bg: linear-gradient(180deg, rgba(250, 248, 242, 0.97), rgba(248, 246, 238, 0.96));
    --glass-panel: linear-gradient(180deg, rgba(251, 249, 244, 0.98), rgba(249, 247, 240, 0.97));
    --glass-fill: rgba(250, 248, 243, 0.98);
  }
  [data-theme="dark"] {
    --glass-bg: linear-gradient(180deg, rgba(46, 45, 41, 0.97), rgba(40, 39, 36, 0.96));
    --glass-panel: linear-gradient(180deg, rgba(46, 45, 41, 0.98), rgba(40, 39, 36, 0.97));
    --glass-fill: rgba(44, 43, 40, 0.98);
  }
}

/* Global reset */
* {
  box-sizing: border-box;
}

body {
  margin: 0;
  padding: 0;
  background: var(--bg-color);
  color: var(--text-color);
  font-family: 'Inter', "PingFang SC", "Microsoft YaHei", sans-serif;
  line-height: 1.8;
  font-size: 16px;
  -webkit-font-smoothing: antialiased;
  -webkit-tap-highlight-color: transparent;
  /* Stop iOS Safari from auto-inflating body text on orientation
     change (it keeps the carefully tuned sizes intact). Doesn't
     affect the user's own pinch-zoom. */
  -webkit-text-size-adjust: 100%;
  text-size-adjust: 100%;
  /* Don't fake italics: CJK system fonts have no italic face, so
     font-style:italic on Chinese text would render an ugly synthetic
     slant. Disabling style synthesis makes CJK render upright while
     real italic faces (EB Garamond) still slant; weight synthesis is
     kept so bold/semibold still work. */
  font-synthesis: weight small-caps;
  /* Theme toggle: body fades its own background/color smoothly.
     Buttons, tags, links etc. carry their own colour transitions
     (0.3s var(--ease)) and pick up the variable change automatically,
     so the whole page inverts in step. */
  transition: background-color 0.3s var(--ease), color 0.3s var(--ease);
}

a {
  color: inherit;
  text-decoration: none;
  transition: color 0.3s var(--ease);
}

a:hover {
  color: var(--accent-color);
}

/* ── Interaction polish ────────────────────────────────────────
   Refined details that make the whole thing feel considered:
   a branded text-selection tint, a clean keyboard focus ring, and
   no grey mobile tap-flash (our own :active states handle feedback). */
::selection { background: color-mix(in srgb, var(--accent-color) 24%, transparent); }

a:focus-visible,
button:focus-visible,
input:focus-visible,
textarea:focus-visible,
[tabindex]:focus-visible {
  outline: 2px solid var(--accent-color);
  outline-offset: 3px;
  border-radius: 4px;
}
/* Mouse users keep the quiet look; only keyboard nav shows the ring */
a:focus:not(:focus-visible),
button:focus:not(:focus-visible) {
  outline: none;
}

/* Skip link — the first Tab stop, letting keyboard and screen-reader
   users jump past the header + nav straight to the article. Sits
   off-screen until focused, then slides in as a solid accent pill.
   Focus lands on <main tabindex="-1"> so the next Tab continues from
   the content. The colour pair inverts cleanly in both themes (ink-bg
   text on the accent), so it never collides with a:hover. */
.skip-link {
  position: fixed;
  left: 12px;
  top: -80px;
  z-index: 100;
  padding: 10px 18px;
  border-radius: 10px;
  background: var(--accent-color);
  font-size: 0.9rem;
  font-weight: 600;
  text-decoration: none;
  box-shadow: var(--glass-drop-pop);
  transition: top 0.25s var(--ease-out);
}
.skip-link,
.skip-link:hover,
.skip-link:focus { color: var(--bg-color); }
.skip-link:focus { top: 12px; outline: none; }
#main-content:focus { outline: none; }

/* Theme-toggle: fade the themed hairlines + post dividers with the
   background instead of letting them snap to the new colour. Border/
   background are sourced from variables, so these fade cleanly at the
   same 0.3s with no inheritance-chasing. */
.related-posts,
.comments-wrapper,
.related-posts li,
.site-footer {
  transition: border-color 0.3s var(--ease);
}
.post-outer + .post-outer::before {
  transition: background-color 0.3s var(--ease);
}

/* Buttons */
.post-tag,
.read-more,
.blog-pager a,
.comment-toggle-btn,
.main-nav li a {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  padding: 8px 14px;
  background: var(--btn-bg);
  color: var(--text-color);
  border: 1px solid transparent;
  border-radius: 30px;
  min-height: 40px;
  transition: background 0.3s var(--ease), color 0.3s var(--ease), transform 0.3s var(--ease-spring), border-color 0.3s var(--ease);
  font-weight: 500;
  font-size: 0.95rem;
  cursor: pointer;
  text-decoration: none;
  font-family: inherit;
  letter-spacing: 0.5px;
}

.main-nav li a {
  font-size: 0.9rem;
}

/* Current section — a quiet sage marker so you always know where
   you are. The .is-active class is set by a synchronous script that
   matches the URL path against each nav link (flash-free). */
.main-nav li a.is-active {
  background: var(--accent-bg);
  color: var(--accent-color);
  font-weight: 600;
}

.comment-toggle-btn {
  padding: 10px 24px;
  min-height: 48px;
}

/* "Read More" + newer/older pager are styled exactly like the nav-bar
   tab buttons: the shared quiet base (neutral fill, sage tint on
   hover) plus the nav's compact font size. */
.read-more,
.blog-pager a {
  font-size: 0.9rem;
}

.read-more {
  margin-top: 15px;
}

.comment-toggle-btn {
  width: 100%;
  max-width: 350px;
  display: flex;
  margin: 0 auto 20px auto;
}

.post-tag:hover,
.read-more:hover,
.blog-pager a:hover,
.comment-toggle-btn:hover,
.main-nav li a:hover {
  background: var(--accent-bg);
  color: var(--accent-color);
  transform: translateY(-2px);
}

.post-tag:active,
.read-more:active,
.blog-pager a:active,
.comment-toggle-btn:active,
.main-nav li a:active {
  transform: scale(0.96);
}

/* ── Primary action — soft tinted pill ─────────────────────────
   "Write a comment" is the one prominent action on an article, so it
   keeps a quiet sage-tinted fill (softer than solid, cleaner than an
   outline) that deepens on hover. Read-More and the pager use the
   quiet nav-tab style instead, so this one tint marks the primary. */
.comment-toggle-btn {
  background: var(--accent-bg);
  color: var(--accent-color);
  border-color: transparent;
  font-weight: 600;
}
.comment-toggle-btn:hover {
  background: var(--accent-bg);
  background: color-mix(in srgb, var(--accent-color) 18%, transparent);
  color: var(--accent-color);
  border-color: transparent;
  transform: translateY(-2px);
}

/* In-article labels — small, quiet text instead of pill buttons,
   middle-dot separated like an editorial meta line
   ("August 2025 · 读书 · 美食"). These tags only render in the
   single-post meta row, so list pages are unaffected. Overrides the
   shared button styling above by source order. */
.post-tag {
  display: inline;
  background: transparent;
  border: none;
  border-radius: 0;
  padding: 0;
  margin: 0;
  min-height: 0;
  font-size: 0.8rem;
  font-weight: 500;
  letter-spacing: 0.3px;
  color: var(--meta-color);
}
.post-tag::before {
  content: '\00B7';
  margin: 0 8px;
  opacity: 0.6;
}
/* No dangling separator before the first tag. On post pages the inline
   date header isn't rendered (it lives in the margin rail), so without
   this the first tag's leading middle-dot floats alone ("· 小说 · …"). */
.post-meta .post-tag:first-child::before { content: none; }
.post-tag:hover {
  background: transparent;
  color: var(--accent-color);
  transform: none;
}

/* Layout */
.outer-wrapper {
  max-width: var(--container-width);
  margin: 0 auto;
  padding: 0 25px;
  position: relative;
}

.site-header,
nav.main-nav,
#main-content,
.site-footer,
.top-actions {
  transition: opacity 0.5s var(--ease-out), transform 0.5s var(--ease-out);
}

.content-fade-out {
  opacity: 0 !important;
  transform: translateY(8px) !important;
  pointer-events: none;
}

/* Toggles */
.top-actions {
  position: absolute;
  top: 30px;
  right: 25px;
  display: flex;
  gap: 12px;
  z-index: 10;
}

.action-btn {
  background: none;
  border: none;
  color: var(--icon-color);
  cursor: pointer;
  border-radius: 50%;
  display: flex;
  align-items: center;
  justify-content: center;
  width: 48px;
  height: 48px;
  transition: background 0.3s var(--ease), color 0.3s var(--ease), transform 0.3s var(--ease-spring);
}

.action-btn:hover {
  background: var(--btn-bg);
  color: var(--accent-color);
  transform: translateY(-2px);
}

#theme-icon {
  width: 22px;
  height: 22px;
  transition: transform 0.5s var(--ease);
}

[data-theme="dark"] #theme-icon {
  transform: rotate(90deg);
}

.sun-icon {
  display: none;
  stroke: currentColor;
  stroke-width: 2;
  stroke-linecap: round;
  stroke-linejoin: round;
  fill: none;
}

.moon-icon {
  display: block;
  fill: currentColor;
  stroke: none;
}

[data-theme="dark"] .sun-icon { display: block; }
[data-theme="dark"] .moon-icon { display: none; }

.text-toggle-btn {
  font-family: 'EB Garamond', serif;
  font-size: 1rem;
  font-weight: 500;
}

/* Language logic */
[data-lang="zh"] .lang-en,
[data-lang="en"] .lang-zh,
[data-variant="simp"] .variant-trad,
[data-variant="trad"] .variant-simp {
  display: none !important;
}

#variant-toggle {
  transition: width 0.3s var(--ease), margin 0.3s var(--ease), opacity 0.3s var(--ease), transform 0.3s var(--ease);
}

[data-lang="en"] #variant-toggle {
  opacity: 0;
  visibility: hidden;
  transform: scale(0.5);
  width: 0;
  margin-left: -12px;
  pointer-events: none;
}

/* Header */
.site-header {
  padding: 80px 0 30px;
  text-align: left;
}

.header-title h1 {
  font-family: 'EB Garamond', serif;
  font-weight: 500;
  /* Fluid headline — scales continuously with viewport (Apple style)
     instead of snapping at a breakpoint. Tuned to equal the old flat
     2.4rem around a 768px laptop and grow to 2.7rem on wide screens;
     the <=600px rule below still pins phones to their own size. */
  font-size: clamp(2.3rem, 2.05rem + 0.7vw, 2.7rem);
  margin: 0;
  letter-spacing: -0.5px;
  word-break: normal;
  overflow-wrap: break-word;
  line-break: strict;
  line-height: 1.3;
}

.header-logo-link {
  display: inline-flex;
  align-items: center;
  justify-content: flex-start;
  gap: 18px;
  border: none !important;
  padding: 12px 0;
  min-height: 60px;
  /* Source the colour straight from the variable (not the global
     a{color:inherit}). If it inherited the body's *animating* colour
     while also carrying its own colour transition, the two would
     compound into a ~0.5s lag behind the body. Keyed to the same var
     change at the same 0.3s, the title now fades in lockstep with it.
     The inner span and the fill:currentColor logo follow this link. */
  color: var(--text-color);
  transition: transform 0.3s var(--ease-spring), color 0.3s var(--ease);
}

.header-logo-link:hover {
  transform: scale(1.02);
}

.header-logo-link svg {
  flex-shrink: 0 !important;
  width: 55px;
  height: 55px;
}

.header-desc {
  /* Cursive tagline under the title — a flowing script, a touch
     larger so it reads comfortably. Script faces already slant, so
     no italic. */
  font-family: 'Dancing Script', cursive;
  font-size: 1.3rem;
  font-weight: 500;
  line-height: 1.4;
  color: var(--meta-color);
  margin-top: 10px;
  font-style: normal;
  /* Left-aligned to sit under the left-aligned title/logo, instead
     of floating centred and out of step with the header. */
  text-align: left;
  max-width: 52ch;
  transition: color 0.3s var(--ease);
}

/* Navigation */
nav.main-nav {
  margin-bottom: 35px;
  text-align: center;
  /* Default: visible — so hover lift renders fully and the few-tab
     common case has zero scrollbar clutter. JS adds .is-scrolling
     when labels actually overflow the container (e.g. user adds an
     8th label), at which point we switch to scroll mode. */
  overflow: visible;
  position: relative;
}
nav.main-nav.is-scrolling {
  overflow-x: auto;
  scrollbar-width: none;
  /* Internal vertical padding gives hover lift breathing room even
     in scroll mode (overflow-x:auto forces overflow-y:auto, which
     would clip the -2px lift). Horizontal padding keeps the first
     tab aligned with the body text's left margin rather than
     hugging the screen edge — same intent as the mobile rule. */
  padding: 6px 20px;
  margin-top: -6px;
  margin-left: -20px;
  margin-right: -20px;
}
nav.main-nav.is-scrolling::-webkit-scrollbar { display: none; }
/* In scroll mode, flex items must align from the start, not center.
   justify-content: center on a flex container wider than its viewport
   centers content visually but locks scroll at position 0, cropping
   both edges. flex-start lets scrollLeft=0 show the leftmost tabs
   intact and the user scrolls right to reveal more. */
nav.main-nav.is-scrolling ul {
  justify-content: flex-start;
}

.main-nav ul {
  margin: 0;
  padding: 0;
  list-style: none;
  display: flex;
  justify-content: center;
  flex-wrap: nowrap;
  gap: 10px;
}

.main-nav li {
  display: inline-block;
  margin: 0;
  flex-shrink: 0;
}

/* Posts */
.post-outer {
  margin-bottom: 70px;
  content-visibility: auto;
  contain-intrinsic-size: 100px 500px;
  position: relative;
}

/* Subtle divider between posts on list pages */
.post-outer + .post-outer::before {
  content: '';
  display: block;
  width: 40px;
  height: 1px;
  background: var(--border-color);
  margin: 0 auto 60px;
  opacity: 0.7;
}

/* ── Infinite scroll UI ────────────────────────────────────────
   An invisible sentinel sits below the last post; IntersectionObserver
   starts loading when it nears the viewport. While loading, a pulsing
   dot row signals activity. End and error states replace the loading
   row with terminating dingbat or a retry button. */
.infinite-sentinel {
  height: 1px;
  margin-top: 40px;
  /* No visual — pure observation target */
}
.infinite-status {
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  margin: 40px auto 60px;
  min-height: 32px;
  color: var(--meta-color);
  font-size: 0.9rem;
  font-family: 'EB Garamond', Georgia, serif;
  font-style: italic;
  opacity: 0;
  transition: opacity 0.4s var(--ease);
}
.infinite-status.is-visible {
  opacity: 1;
}
/* Loading: a single sage dot that pulses */
.infinite-status .loading-dot {
  width: 8px;
  height: 8px;
  border-radius: 50%;
  background: var(--accent-color);
  animation: infinite-pulse 1.4s ease-in-out infinite;
}
@keyframes infinite-pulse {
  0%, 100% { opacity: 0.3; transform: scale(0.9); }
  50%      { opacity: 1;   transform: scale(1.1); }
}
@media (prefers-reduced-motion: reduce) {
  .infinite-status .loading-dot { animation: none; opacity: 0.7; }
}
/* End-of-list: three centered dots, same dingbat as hr */
.infinite-status .end-dingbat {
  color: var(--meta-color);
  letter-spacing: 0.8em;
  font-size: 0.85rem;
  padding-left: 0.8em;
}
/* Error: text + retry button stacked */
.infinite-status .retry-btn {
  margin-top: 8px;
  background: var(--btn-bg);
  color: var(--text-color);
  border: 1px solid transparent;
  border-radius: 30px;
  padding: 6px 18px;
  font-size: 0.85rem;
  font-family: inherit;
  font-style: normal;
  cursor: pointer;
  transition: background 0.3s var(--ease), color 0.3s var(--ease), transform 0.3s var(--ease-spring);
}
.infinite-status .retry-btn:hover {
  background: var(--accent-bg);
  color: var(--accent-color);
  transform: translateY(-1px);
}

h2.post-title {
  font-family: 'EB Garamond', serif;
  /* Fluid like the header: ≈1.85rem at laptop widths, up to 2.05rem
     on wide screens; the <=600px rule keeps phones at 1.4rem. */
  font-size: clamp(1.8rem, 1.62rem + 0.48vw, 2.05rem);
  margin: 0 0 10px;
  line-height: 1.45;
  font-weight: 500;
  /* Slight negative tracking on the large serif title — the same
     display refinement Anthropic/Apple use on big headlines. Reset
     for CJK below, where tighter tracking reads cramped. */
  letter-spacing: -0.3px;
  word-break: normal;
  overflow-wrap: anywhere;
  text-wrap: balance;
  hyphens: auto;
  /* NO own colour/transition: the title inherits the body's colour and
     follows its 0.3s fade exactly, like the body paragraphs do. Giving
     it its own colour transition made it *chase* the body's animation
     instead, compounding into the ~0.5s lag. */
}

/* Chinese titles: allow breaking between any characters to prevent overflow,
   and skip text-wrap:balance so punctuation can land where CJK rules dictate */
h2.post-title:lang(zh),
h2.post-title[lang^="zh"] {
  word-break: break-word;
  overflow-wrap: break-word;
  text-wrap: auto;
  line-break: strict;
  letter-spacing: normal;
}

h2.post-title a {
  border: none;
  display: inline-block;
  padding: 10px 0;
  min-height: 48px;
  /* Explicit var colour so theme-switch fade and hover→accent are
     both clean (no inherit-chasing lag). */
  color: var(--text-color);
  transition: color 0.3s var(--ease), transform 0.3s var(--ease-spring);
}

h2.post-title a:hover {
  color: var(--accent-color);
  transform: translateX(2px);
}


.post-meta {
  font-size: 0.85rem;
  /* Old-style figures so the date numerals sit as editorial text,
     consistent with the article headings, quotes and margin rails. */
  font-feature-settings: "onum" 1, "liga" 1;
  color: var(--meta-color);
  margin-bottom: 20px;
  letter-spacing: 0.5px;
  display: flex;
  flex-wrap: wrap;
  align-items: center;
  transition: color 0.3s var(--ease);
}

.post-body.full-content {
  font-size: 1.15rem;
  word-break: break-word;
  /* Editorial polish: enable ligatures + contextual alternates so
     Inter sets cleanly, and let the browser optimise legibility. */
  font-feature-settings: "liga" 1, "calt" 1;
  text-rendering: optimizeLegibility;
}

/* Lead paragraph — the opening paragraph reads a touch larger and
   calmer, an editorial intro in the spirit of Anthropic's long-form
   pages. Language-safe: no drop cap (CJK can't take one cleanly). */
.post-body.full-content > p:first-of-type {
  font-size: 1.22rem;
  line-height: 1.85;
}

.post-body a {
  /* Explicit var colour (not inherited) so the theme-toggle fade
     can't compound into a lag behind the body — same fix as the
     titles. Hover→accent stays clean too. */
  color: var(--text-color);
  text-decoration: underline;
  text-decoration-thickness: 1px;
  text-underline-offset: 4px;
  text-decoration-color: color-mix(in srgb, currentColor 50%, transparent);
  transition: color 0.3s var(--ease), text-decoration-color 0.3s var(--ease);
}

.post-body a:hover {
  color: var(--accent-color);
  text-decoration-color: var(--accent-color);
}

.post-body a:has(img) {
  text-decoration: none;
  display: block;
}

/* Images sit flatter now — a soft, tight shadow rather than a big
   floaty one, in keeping with Anthropic's flat-surface aesthetic. */
.post-body img {
  max-width: 100%;
  height: auto;
  border-radius: 8px;
  margin: 30px auto;
  display: block;
  box-shadow: 0 2px 8px rgba(0, 0, 0, 0.06);
  transition: transform 0.5s var(--ease-out), box-shadow 0.5s var(--ease-out);
}

[data-theme="dark"] .post-body img {
  box-shadow: 0 2px 8px rgba(0, 0, 0, 0.3);
}

.post-body img:hover {
  transform: scale(1.01);
  box-shadow: 0 3px 12px rgba(0, 0, 0, 0.09);
}

[data-theme="dark"] .post-body img:hover {
  box-shadow: 0 3px 12px rgba(0, 0, 0, 0.4);
}

.separator {
  border: none !important;
  background: transparent !important;
}

/* Section break — replace the default 1px line with three centered
   dots, like a typesetter's flourish between scenes. Pure CSS, the
   hr stays semantic (still announces as a separator to screen readers). */
.post-body hr {
  border: none;
  background: none;
  margin: 2.5em auto;
  height: auto;
  text-align: center;
  overflow: visible;
}
.post-body hr::before {
  /* \0000B7 is the CSS Unicode escape for U+00B7 (middle dot), using
     the full 6-digit form so no whitespace terminator is needed.
     Using escapes instead of the literal character prevents Blogger's
     XML serializer from emitting "&#183;" on output. The three dots
     are spaced apart purely via letter-spacing — no literal spaces
     in the string. */
  content: '\0000B7\0000B7\0000B7';
  display: block;
  color: var(--meta-color);
  letter-spacing: 0.8em;
  font-size: 0.85em;
  line-height: 1;
  /* Subtract half the letter-spacing on the right so the dots are
     optically centered (otherwise the trailing letter-spacing
     pushes them left) */
  padding-left: 0.8em;
}

/* ── Rich article content ──────────────────────────────────────
   Long-form bodies contain headings, quotes, lists, code and
   tables that Blogger emits with no classes, so without these
   rules they fall back to raw browser defaults and break the
   warm-paper, Garamond-and-Inter rhythm. Scoped to .full-content
   so list-page snippets stay untouched. Purely visual — no logic
   depends on any of these selectors. */

/* Section headings inside an article. Garamond like every other
   heading in the theme; sizes step down from the 1.85rem post
   title so the document hierarchy reads cleanly. */
.post-body.full-content h2,
.post-body.full-content h3,
.post-body.full-content h4 {
  font-family: 'EB Garamond', serif;
  font-weight: 500;
  line-height: 1.35;
  color: var(--text-color);
  margin: 1.8em 0 0.5em;
  letter-spacing: -0.2px;
  /* Old-style figures let any numerals in headings sit like text */
  font-feature-settings: "onum" 1, "liga" 1;
  /* Balance short multi-line subheads so no lonely last word hangs —
     a modern refinement; older browsers simply ignore it. */
  text-wrap: balance;
}
.post-body.full-content h2 { font-size: 1.6rem; }
.post-body.full-content h3 { font-size: 1.35rem; }
.post-body.full-content h4 { font-size: 1.12rem; font-weight: 600; }
/* No runaway top gap when a heading opens the article */
.post-body.full-content > :first-child { margin-top: 0; }

/* Blockquote — a quiet sage rule in the margin rather than a heavy
   bar. Serif + meta colour gives it a "set apart" voice. Not
   italicised: synthetic-slanted CJK reads poorly. */
.post-body.full-content blockquote {
  margin: 1.8em 0;
  padding: 0.2em 0 0.2em 1.4em;
  border-left: 3px solid var(--accent-color);
  color: var(--meta-color);
  font-family: 'EB Garamond', Georgia, serif;
  font-size: 1.2rem;
  line-height: 1.7;
  /* Old-style figures + balanced wrap so any year/number in a pull
     quote sits like running text and the lines break evenly. */
  font-feature-settings: "onum" 1, "liga" 1;
  text-wrap: pretty;
}
.post-body.full-content blockquote p { margin: 0.5em 0; }
.post-body.full-content blockquote p:first-child { margin-top: 0; }
.post-body.full-content blockquote p:last-child { margin-bottom: 0; }

/* Lists — comfortable indent, sage/meta markers */
.post-body.full-content ul,
.post-body.full-content ol {
  padding-left: 1.4em;
  margin: 1.2em 0;
}
.post-body.full-content li { margin: 0.5em 0; text-wrap: pretty; }
.post-body.full-content ul li::marker { color: var(--accent-color); }
.post-body.full-content ol li::marker { color: var(--meta-color); }
.post-body.full-content li > ul,
.post-body.full-content li > ol { margin: 0.4em 0; }

/* Inline code + fenced blocks share the quiet button-bg tint */
.post-body.full-content code {
  font-family: 'SFMono-Regular', 'JetBrains Mono', Menlo, Consolas, monospace;
  font-size: 0.88em;
  background: var(--btn-bg);
  padding: 0.15em 0.4em;
  border-radius: 5px;
  word-break: break-word;
}
.post-body.full-content pre {
  background: var(--btn-bg);
  border: 1px solid var(--border-color);
  border-radius: 8px;
  padding: 16px 18px;
  overflow-x: auto;
  font-size: 0.9rem;
  line-height: 1.6;
  margin: 1.6em 0;
}
.post-body.full-content pre code {
  background: none;
  padding: 0;
  border-radius: 0;
  font-size: inherit;
  word-break: normal;
}

/* Tables — hairline borders, tinted header row */
.post-body.full-content table {
  width: 100%;
  border-collapse: collapse;
  margin: 1.8em 0;
  font-size: 0.95rem;
}
.post-body.full-content th,
.post-body.full-content td {
  border: 1px solid var(--border-color);
  padding: 10px 14px;
  text-align: left;
}
.post-body.full-content th {
  background: var(--btn-bg);
  font-weight: 600;
}

/* Figures — keep the caption tucked under its image as a small
   italic meta note (the global img margin would otherwise leave a
   30px gap between picture and caption). */
.post-body.full-content figure { margin: 30px 0; }
.post-body.full-content figure img { margin: 0 auto 8px; }
.post-body.full-content figcaption {
  font-family: 'EB Garamond', Georgia, serif;
  font-style: italic;
  font-size: 0.9rem;
  color: var(--meta-color);
  text-align: center;
}

/* Comfortable paragraph rhythm — explicit spacing so prose breathes
   evenly regardless of how Blogger emits the markup. */
/* text-wrap: pretty evens out line lengths and kills orphans/rivers
   the way fine typesetting does — Apple/Anthropic-grade prose polish.
   Purely presentational; unsupported browsers ignore it. */
.post-body.full-content p { margin: 0 0 1.4em; text-wrap: pretty; }

/* Homepage preview reads like the real article: same body size, full
   opacity, same editorial polish — no dim/hover-brighten. It's kept
   concise by the length cap in the markup (snippet length), not by
   shrinking or fading the text. Line-height is set per-language by the
   typography JS pass (same as the article body), so none here. */
.post-body.snippet-content {
  font-size: 1.15rem;
  color: var(--text-color);
  margin-bottom: 18px;
  font-feature-settings: "liga" 1, "calt" 1;
  text-rendering: optimizeLegibility;
}

.featured-img-wrapper {
  display: block;
  overflow: hidden;
  border-radius: 8px;
  margin-bottom: 18px;
}

.featured-img-wrapper img {
  width: 100%;
  aspect-ratio: 16/9;
  height: auto;
  object-fit: cover;
  border-radius: 8px;
  margin-bottom: 0;
  display: block;
  box-shadow: none;
  transition: transform 0.6s var(--ease-out);
}

.featured-img-wrapper:hover img {
  transform: scale(1.03);
  box-shadow: none;
}

/* Pagination */
.blog-pager {
  padding: 10px 0;
  text-align: center;
  font-size: 0.95rem;
  display: flex;
  justify-content: center;
  flex-wrap: wrap;
  gap: 16px;
}

/* Related posts & headers */
.related-posts,
.comments-wrapper {
  margin-top: 30px;
  padding-top: 20px;
  border-top: 1px solid var(--border-color);
}

.related-posts h3,
.comments-wrapper h3 {
  font-family: 'EB Garamond', serif;
  font-size: 1.5rem;
  margin-bottom: 15px;
  font-weight: 500;
}

/* Related posts — a clean row list with hairline dividers. On hover
   the title slides right and a sage arrow glides in from the left,
   an editorial cue rather than the old dashed underline. */
.related-posts ul {
  list-style: none;
  padding: 0;
  margin: 0;
}
.related-posts li { border-top: 1px solid var(--border-color); }
.related-posts li:first-child { border-top: none; }
.related-posts li a {
  display: block;
  position: relative;
  font-size: 1.05rem;
  color: var(--text-color);
  padding: 12px 0;
  transition: color 0.3s var(--ease), padding-left 0.3s var(--ease);
}
.related-posts li a::before {
  content: '\2192';
  position: absolute;
  left: 0;
  color: var(--accent-color);
  opacity: 0;
  transform: translateX(-6px);
  transition: opacity 0.3s var(--ease), transform 0.3s var(--ease);
}
.related-posts li a:hover {
  color: var(--accent-color);
  padding-left: 22px;
}
.related-posts li a:hover::before {
  opacity: 1;
  transform: translateX(0);
}

/* Comments */
.comments {
  position: relative;
  padding-left: 0;
}

.comments .comment::before,
.comments .comment::after,
.comments .comment-thread ol::before,
.comments .comment-thread ol::after,
#comment-holder > .comment-replybox-thread,
.comment-thread .comment-replybox-thread {
  display: none !important;
  content: none !important;
  height: 0 !important;
  border: none !important;
}

#custom-comment-form-container {
  display: grid;
  grid-template-rows: 0fr;
  opacity: 0;
  margin-top: 0;
  margin-bottom: 0;
  width: 100%;
  position: relative;
  pointer-events: none;
  transition: grid-template-rows 0.3s var(--ease), opacity 0.25s var(--ease), margin 0.3s var(--ease);
}

#custom-comment-form-container.is-expanded {
  grid-template-rows: 1fr;
  opacity: 1;
  pointer-events: auto;
}

/* Open form spacing: 15px vertical gap. When the form follows the main
   toggle button directly inside .comments-wrapper, pull it up 5px to
   tuck closer to the button. The selector covers both placements
   (top-level main form and inline reply form) without duplication. */
#custom-comment-form-container.is-expanded {
  margin-top: 15px;
  margin-bottom: 15px;
}
.comments-wrapper > #custom-comment-form-container.is-expanded {
  margin-top: -5px;
}

.form-inner {
  min-height: 0;
  display: flex;
  flex-direction: column;
  transform: translateZ(0);
  overflow-x: auto;
  overflow-y: hidden;
  direction: rtl;
  scrollbar-width: none;
}

.form-inner::-webkit-scrollbar {
  display: none;
}

.comments-wrapper iframe#comment-editor {
  margin-left: 0 !important;
  border: none;
  background: transparent !important;
  height: 100px !important;
  transition: filter 0.3s var(--ease);
  color-scheme: light !important;
  direction: ltr;
  width: calc(100% + 54px) !important;
  max-width: none !important;
  flex-shrink: 0;
  /* Re-tint the iframe's pure-white body to the warm ivory paper bg
     (#faf9f4 = rgb 250,249,244). sepia(0.35) drops the blue channel to
     ~244 for the warmth; brightness(0.98) lands red/green on ~250 —
     hitting the exact paper tone so the editor disappears into it. */
  filter: sepia(0.35) brightness(0.98);
}

[data-theme="dark"] .comments-wrapper iframe#comment-editor {
  /* Land the body on the warm charcoal bg (#1a1915 ≈ rgb 26,25,21).
     invert(0.9) flips white→rgb(26) grey; hue-rotate keeps any
     coloured text sane; brightness(0.89)+sepia(0.42) then warm it
     down to ≈ rgb(26,25,22) — effectively the same tone as the bg,
     so the editor blends instead of reading as a cool grey box. */
  filter: invert(0.9) hue-rotate(180deg) brightness(0.89) sepia(0.42) !important;
}

h4#comment-post-message,
.comment-thread-toggle,
.thread-toggle,
.continue,
.loadmore,
.paging-control-container,
.titlewrapper,
.quickedit,
.post-feeds,
#Attribution1,
.thread-count,
.icon.action {
  display: none !important;
  visibility: hidden !important;
  opacity: 0 !important;
  height: 0 !important;
  width: 0 !important;
}

.comments .comment {
  position: relative;
  padding-left: 56px;
  margin-bottom: 24px;
  list-style: none !important;
  overflow: visible !important;
  padding-bottom: 0 !important;
}

.comments .comment-block {
  margin-left: 0 !important;
  padding: 0 !important;
}

.thread-trunk {
  position: absolute !important;
  left: 19px !important;
  top: 45px !important;
  bottom: 52px !important;
  width: 2px !important;
  background-color: var(--border-color) !important;
  z-index: 1 !important;
}

.comment-header {
  display: flex;
  align-items: center;
  flex-wrap: wrap;
  gap: 8px;
  margin-bottom: 4px;
}

.comment-author,
.datetime {
  display: inline-flex;
  align-items: center;
}

.comment-author a,
.datetime a {
  padding: 0;
  min-height: auto;
  border: none;
  transition: color 0.3s var(--ease);
}

.comment-author {
  font-weight: 600;
  font-size: 0.95rem;
  /* Explicit colour so the author link inside fades cleanly on toggle
     rather than chasing the body's animating colour. (.datetime
     already sets its own colour, so it's fine.) */
  color: var(--text-color);
}

.datetime {
  font-size: 0.85rem;
  color: var(--meta-color);
}

.comment-content {
  font-size: 0.95rem;
  line-height: 1.6;
  margin-bottom: 4px;
  word-break: break-word;
  border: none !important;
  padding: 0 !important;
  background: transparent !important;
}

.avatar-image-container {
  position: absolute !important;
  left: 0;
  top: 0 !important;
  width: 40px !important;
  height: 40px !important;
  margin: 0 !important;
}

.avatar-image-container img {
  width: 100%;
  height: 100%;
  border-radius: 50%;
  object-fit: cover;
}

.comments .item-control {
  display: flex !important;
  flex-wrap: wrap;
  gap: 16px;
  margin-top: 6px;
  align-items: center;
}

.item-control .comment-reply {
  display: inline-flex !important;
}

.comments .item-control a {
  min-height: auto;
  padding: 6px 12px;
  font-size: 0.85rem;
  font-weight: 600;
  border-radius: 16px;
  background: transparent !important;
  border: none !important;
  color: var(--text-color);
  transition: background 0.2s var(--ease);
  cursor: pointer;
}

.comments .item-control a:hover {
  background: var(--btn-bg) !important;
  transform: none;
}

.comment-replies ol,
.comment-replies ul,
.comment-thread ol,
.comment-thread ul {
  margin-left: 0 !important;
  padding-left: 0 !important;
  margin: 0 !important;
  padding: 0 !important;
  list-style: none !important;
  border: none !important;
}

.comment-replies {
  position: relative !important;
  margin: 12px 0 0 -20px !important;
  padding: 0 !important;
}

.comment-replies .comment {
  padding: 0 0 0 36px !important;
  margin: 0 0 16px 0 !important;
  position: relative !important;
  overflow: visible !important;
}

.comment-replies .avatar-image-container {
  width: 24px !important;
  height: 24px !important;
  left: 0 !important;
  top: 0 !important;
  margin: 0 !important;
  padding: 0 !important;
  z-index: 2 !important;
  position: absolute !important;
}

.yt-branch {
  display: block !important;
  position: absolute !important;
  box-sizing: border-box !important;
  left: -17px !important;
  top: -20px !important;
  width: 17px !important;
  height: 32px !important;
  border-left: 2px solid var(--border-color) !important;
  border-bottom: 2px solid var(--border-color) !important;
  border-bottom-left-radius: 16px !important;
  border-top: none !important;
  border-right: none !important;
  background-color: transparent !important;
  z-index: 1 !important;
  pointer-events: none !important;
}

.replies-grid-wrapper {
  display: grid;
  grid-template-rows: 0fr;
  opacity: 0;
  pointer-events: none;
  transition: grid-template-rows 0.4s var(--ease-out), opacity 0.35s var(--ease);
}

.replies-grid-wrapper.is-expanded {
  grid-template-rows: 1fr;
  opacity: 1;
  pointer-events: auto;
}

.replies-grid-inner {
  min-height: 0;
  overflow: hidden;
  padding-top: 4px;
  margin-left: -30px !important;
  padding-left: 30px !important;
}

.reply-toggle-btn {
  position: relative;
  background: transparent !important;
  color: var(--accent-color) !important;
  font-weight: 600;
  font-size: 0.9rem;
  padding: 6px 16px;
  margin: 0 0 12px 0 !important;
  border-radius: 18px;
  display: inline-flex;
  align-items: center;
  gap: 6px;
  min-height: 32px;
  transition: background 0.2s var(--ease);
  cursor: pointer;
  border: none;
  font-family: inherit;
  z-index: 2;
}

.reply-toggle-btn:hover {
  background: var(--accent-bg) !important;
  transform: none !important;
}

.reply-toggle-btn svg {
  width: 20px;
  height: 20px;
  transition: transform 0.3s var(--ease);
  fill: currentColor;
}

.reply-toggle-btn.expanded svg {
  transform: rotate(180deg);
}

.reply-toggle-btn::before {
  content: '' !important;
  display: block !important;
  position: absolute !important;
  box-sizing: border-box !important;
  left: -17px !important;
  top: -16px !important;
  width: 17px !important;
  height: 32px !important;
  border-left: 2px solid var(--border-color) !important;
  border-bottom: 2px solid var(--border-color) !important;
  border-bottom-left-radius: 16px !important;
  border-top: none !important;
  border-right: none !important;
  pointer-events: none !important;
  z-index: 1 !important;
}

/* Footer — Anthropic-style airy rhythm: more space above the rule
   and around the social row so the page closes calmly. */
.site-footer {
  padding: 50px 0 40px;
  border-top: 1px solid var(--border-color);
  text-align: center;
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 24px;
  margin-top: 60px;
}

.social-links {
  display: flex;
  gap: 16px;
  justify-content: center;
}

.social-links a {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  width: 48px;
  height: 48px;
  background: none;
  border-radius: 50%;
  border: none;
  /* Unified with the header .action-btn icon buttons: bare by default,
     a quiet bg + sage on hover, same -2px lift. Explicit var colour
     keeps the icon's fill:currentColor fading cleanly on theme toggle. */
  color: var(--icon-color);
  transition: background 0.3s var(--ease), color 0.3s var(--ease), transform 0.3s var(--ease-spring);
}

.social-links a:hover {
  background: var(--btn-bg);
  color: var(--accent-color);
  transform: translateY(-2px);
}

.social-links svg {
  width: 24px;
  height: 24px;
  fill: currentColor;
}

.copyright-text {
  font-size: 0.85rem;
  color: var(--meta-color);
  padding: 12px 0;
  min-height: 48px;
}

/* Mobile layout */
@media (max-width: 600px) {
  .outer-wrapper { padding: 0 20px; }
  .site-header { padding: 60px 0 20px; text-align: left; }
  .header-logo-link svg { width: 65px !important; height: 65px !important; }
  .header-logo-link { flex-direction: row !important; align-items: center !important; gap: 12px !important; }
  .header-title h1 { font-size: 1.8rem; line-height: 1.3; }

  h2.post-title {
    font-size: 1.4rem;
    line-height: 1.4;
  }

  .post-outer {
    margin-bottom: 50px;
  }

  .post-outer + .post-outer::before {
    margin: 0 auto 45px;
  }

  .post-meta {
    font-size: 0.8rem;
    margin-bottom: 16px;
  }

  nav.main-nav {
    overflow-x: auto;
    -webkit-overflow-scrolling: touch;
    scrollbar-width: none;
    margin-left: -20px;
    margin-right: -20px;
    padding: 5px 20px;
    margin-top: -5px;
  }

  nav.main-nav::-webkit-scrollbar { display: none; }
  nav.main-nav ul { flex-direction: row; align-items: center; justify-content: flex-start; flex-wrap: nowrap; gap: 10px; }
  .main-nav li { margin: 0; flex-shrink: 0; }
  .main-nav li a { padding: 6px 16px; min-height: 38px; font-size: 0.85rem; }

  .comments .comment { padding-left: 46px !important; }
  .avatar-image-container { width: 34px !important; height: 34px !important; }
  .thread-trunk { left: 16px !important; top: 38px !important; bottom: 48px !important; }

  .comment-replies { margin-left: -16px !important; }
  .comment-replies .comment { padding-left: 28px !important; }
  .comment-replies .avatar-image-container { width: 20px !important; height: 20px !important; }
  .replies-grid-inner { margin-left: -20px !important; padding-left: 20px !important; }

  .yt-branch { left: -14px !important; width: 14px !important; height: 26px !important; top: -16px !important; border-bottom-left-radius: 12px !important; }
  .reply-toggle-btn::before { left: -14px !important; width: 14px !important; height: 26px !important; top: -10px !important; border-bottom-left-radius: 12px !important; }
}

/* ========================================================
   Desktop layout — Plan C: restrained marginalia
   Reading column stays 700px (identical typography to mobile).
   Adds three subtle desktop-only flourishes at >=1024px:
     1. Date label in the left margin (vertical for CJK)
     2. Reading-time label in the right margin (mirror of #1)
     3. Hover marker line beside the paragraph under the cursor
   All purely additive — nothing in the reading flow changes.
   ======================================================== */
@media (min-width: 1024px) {

  /* ── Margin notes: date (left) + read time (right) ────── */
  /* Both rails sit vertically centered on the viewport so they
     read as a balanced pair of page margin notes. Chinese gets
     vertical writing (square characters handle it well); Latin
     stays horizontal (rotated Latin glyphs are hard to read). */
  .desktop-date-rail,
  .desktop-readtime-rail {
    position: fixed;
    top: 50%;
    transform: translateY(-50%);
    font-family: 'EB Garamond', 'Cormorant Garamond', Georgia, serif;
    font-style: italic;
    /* Old-style figures so the year in the date rail reads as
       manuscript marginalia rather than tabular digits. */
    font-feature-settings: "onum" 1, "liga" 1;
    font-size: 0.85rem;
    color: var(--meta-color);
    opacity: 0;
    transition: opacity 0.6s var(--ease) 0.4s;
    pointer-events: none;
    user-select: none;
    z-index: 5;
  }
  .desktop-date-rail.is-ready,
  .desktop-readtime-rail.is-ready {
    opacity: 0.7;
  }
  .desktop-date-rail {
    left: 32px;
  }
  .desktop-readtime-rail {
    right: 32px;
    text-align: right;
  }
  /* Chinese variant: vertical, traditional manuscript feel */
  .desktop-date-rail .lang-zh,
  .desktop-readtime-rail .lang-zh {
    writing-mode: vertical-rl;
    font-family: 'Noto Serif CJK SC', 'Songti SC', serif;
    font-style: normal;
    letter-spacing: 2px;
  }
  /* English variant: horizontal small caps, like a foot mark */
  .desktop-date-rail .lang-en {
    letter-spacing: 4px;
    white-space: nowrap;
  }
  /* Read-time English: slightly tighter tracking since digits don't
     need as much air as month names */
  .desktop-readtime-rail .lang-en {
    letter-spacing: 1.5px;
    white-space: nowrap;
  }
}

/* ── Reading progress bar + tap-to-top ─────────────────────────
   A thin sage line pinned to the bottom edge fills as the reader
   descends, and the whole strip (with a taller invisible hit area)
   is tappable to glide back to the top. A small bilingual hint pill
   teaches the gesture — it appears when the bar first shows and again
   when reading completes, then auto-fades. Desktop + mobile. */
.reading-bar {
  position: fixed;
  left: 0;
  right: 0;
  bottom: 0;
  height: 3px;
  background: var(--border-color);
  opacity: 0;
  transition: opacity 0.5s var(--ease), height 0.2s var(--ease), background 0.3s var(--ease);
  pointer-events: none;
  z-index: 6;
  cursor: pointer;
}
.reading-bar.is-active {
  opacity: 1;
  pointer-events: auto;
}
/* Taller transparent hit area so the thin line is easy to tap/click */
.reading-bar::before {
  content: '';
  position: absolute;
  left: 0;
  right: 0;
  bottom: 0;
  height: 20px;
}
.reading-bar .bar-fill {
  height: 100%;
  width: 100%;
  transform: scaleX(0);
  transform-origin: left center;
  background: var(--accent-color);
  /* Animate transform (compositor-only) rather than width (re-layouts
     every frame) for a buttery fill; a short linear tween smooths the
     gaps between scroll samples without feeling laggy. */
  transition: transform 0.1s linear, background 0.3s var(--ease);
  will-change: transform;
}
/* Thicken slightly on hover to signal it's interactive */
.reading-bar:hover {
  height: 5px;
}

/* Floating hint pill — a small dark/light capsule above the bar that
   explains the tap-to-top gesture. Bilingual via lang spans, so it
   follows the site language toggle. */
/* A quiet paper pill in the theme's editorial-note voice: warm bg, a
   hairline border, EB Garamond italic in meta grey, with a small sage
   arrow tying it to the progress bar. Same palette/variables as the
   margin rails, figure captions and quiet buttons. */
.reading-hint {
  position: fixed;
  bottom: 18px;
  left: 50%;
  transform: translateX(-50%) translateY(8px);
  background: var(--glass-bg);
  -webkit-backdrop-filter: var(--glass-blur);
  backdrop-filter: var(--glass-blur);
  color: var(--meta-color);
  font-family: 'EB Garamond', Georgia, serif;
  font-style: italic;
  font-size: 0.95rem;
  letter-spacing: 0.2px;
  padding: 7px 18px;
  border: none;
  border-radius: 22px;
  white-space: nowrap;
  opacity: 0;
  pointer-events: none;
  transition: opacity 0.4s var(--ease), transform 0.4s var(--ease-out), background 0.3s var(--ease), color 0.3s var(--ease);
  z-index: 7;
  box-shadow: var(--glass-drop), var(--glass-edge);
}
.reading-hint .hint-arrow {
  color: var(--accent-color);
  font-style: normal;
  font-weight: 600;
  margin-right: 7px;
}
/* Chinese reads upright — Garamond italic is lovely for Latin but CJK
   has no italic face. (Belt-and-suspenders with the global
   font-synthesis rule, and guaranteed on older browsers too.) */
.reading-hint .lang-zh {
  font-style: normal;
}
.reading-hint.is-shown {
  opacity: 1;
  transform: translateX(-50%) translateY(0);
}

/* Reopen desktop block for the paragraph hover marker
   (this one IS desktop-only — touch devices have no hover state) */
@media (min-width: 1024px) {

  /* ── Paragraph hover marker — extremely subtle ────────── */
  /* Only applies inside long-form article body. A tiny vertical
     line appears in the left margin when hovering a paragraph,
     like a faint editor's mark. Stays under the radar but adds
     a touch of life to the reading column. */
  .post-body.full-content > p,
  .post-body.full-content > blockquote {
    position: relative;
  }
  .post-body.full-content > p::before,
  .post-body.full-content > blockquote::before {
    content: '';
    position: absolute;
    left: -22px;
    top: 0.6em;
    width: 2px;
    height: 1.2em;
    /* Fallback for browsers without color-mix support */
    background: var(--border-color);
    background: color-mix(in srgb, var(--meta-color) 35%, transparent);
    opacity: 0;
    transition: opacity 0.4s var(--ease);
    pointer-events: none;
  }
  .post-body.full-content > p:hover::before,
  .post-body.full-content > blockquote:hover::before {
    opacity: 1;
  }
  /* Honor the reduced-motion preference — no marker fade */
  @media (prefers-reduced-motion: reduce) {
    .post-body.full-content > p::before,
    .post-body.full-content > blockquote::before {
      transition: none;
    }
  }
}

/* Margin rails are desktop-only. Progress bar + scroll-to-top render
   on both desktop and mobile — they're useful on long article
   scrolls regardless of viewport. */
@media (max-width: 1023px) {
  .desktop-date-rail,
  .desktop-readtime-rail {
    display: none !important;
  }
}

/* ── Mascot ──────────────────────────────────────────────────────
   A chibi figure in the bottom-left corner with a warm paper speech
   bubble. Built/driven by JS; styled here in the theme's palette. */
.mascot {
  position: fixed;
  left: 16px;
  bottom: 0;
  width: 172px;
  z-index: 30;                  /* above the top toggles (z-10) so the open menu is never covered */
  opacity: 0;
  transform: translateY(16px);
  transition: opacity 0.5s var(--ease-out), transform 0.5s var(--ease-out);
  /* The container box equals the figure (bubble, gear and menu are
     absolutely positioned), so it only sits in the corner — fine to be
     interactive there so :hover reveals the gear. */
}
/* Invisible hover-detection halo: extends the interactive area beyond
   the figure (especially upward, where the gear bar floats) so moving
   the pointer toward the button doesn't cross a dead zone and lose the
   :hover state. Sits behind the figure so it never steals its clicks. */
.mascot::before {
  content: "";
  position: absolute;
  left: -16px;
  right: -16px;
  top: -52px;
  bottom: -52px;
  z-index: -1;
}
.mascot.is-ready { opacity: 1; transform: translateY(0); }
.mascot.is-hidden {
  opacity: 0;
  transform: translateY(16px);
  visibility: hidden;
  pointer-events: none;
}
.mascot-img {
  width: 100%;
  height: auto;
  display: block;
  cursor: grab;
  pointer-events: auto;
  user-select: none;
  -webkit-user-drag: none;
  filter: drop-shadow(0 8px 16px rgba(0, 0, 0, 0.16));
  animation: mascot-bob 4.5s ease-in-out infinite;
}
@keyframes mascot-bob {
  0%, 100% { transform: translateY(0); }
  50%      { transform: translateY(-6px); }
}

/* ── Reduced-motion: respect the OS "minimize motion" setting ──────
   Switch off the looping idle bob and the larger zoom-on-hover scales
   — the showy, continuous/large motions Apple disables under this
   preference. Quiet hover feedback (the small button/icon lifts) is
   kept, and functional transitions (collapse, fades, theme toggle)
   are untouched so nothing breaks. */
@media (prefers-reduced-motion: reduce) {
  .mascot-img { animation: none; }
  .post-body img:hover,
  .featured-img-wrapper:hover img { transform: none; }
  /* Calm the popovers: let the bubble and settings menu fade in place
     rather than springing/sliding (opacity still handles show/hide).
     Scoped to these two — NOT .mascot itself, whose transform drives
     the edge-tuck positioning. */
  .mascot-bubble,
  .mascot-menu { transform: none !important; }
}
[data-theme="dark"] .mascot-img {
  filter: drop-shadow(0 8px 18px rgba(0, 0, 0, 0.5));
}
/* While dragging: hold still, lift off the page, tuck the bubble away */
.mascot-dragging .mascot-img {
  animation: none;
  cursor: grabbing;
  filter: drop-shadow(0 14px 24px rgba(0, 0, 0, 0.22));
}
[data-theme="dark"] .mascot-dragging .mascot-img {
  filter: drop-shadow(0 14px 26px rgba(0, 0, 0, 0.55));
}
/* While the size slider is dragged: scale the figure on the GPU only
   (the container box stays put, so the menu/slider don't jump), and
   drop the bob + shadow so it's smooth. Real width commits on release. */
.mascot-resizing .mascot-img {
  animation: none;
  filter: none;
  transform-origin: center bottom;
}
/* Stop compositing the bob when the figure is dismissed or resting
   tucked — no point animating something that's invisible/parked. */
.mascot.is-hidden .mascot-img,
.mascot.is-tucked .mascot-img { animation-play-state: paused; }
/* Dragged mostly off-screen → fade to signal "let go to hide". */
.mascot-dragging.mascot-will-hide { opacity: 0.45; }
.mascot-dragging .mascot-bubble { opacity: 0 !important; }
/* Smooth glide for edge-snap and double-tap-home */
.mascot.mascot-snapping {
  transition: left 0.38s var(--ease-out), top 0.38s var(--ease-out),
              opacity 0.5s var(--ease-out), transform 0.5s var(--ease-out);
}
/* Speech bubble floats above the figure */
.mascot-bubble {
  position: absolute;
  bottom: 100%;
  left: 22px;                       /* grows rightward from over the figure */
  transform: translateY(6px) scale(0.96);
  transform-origin: bottom left;
  margin-bottom: 4px;
  max-width: 210px;
  width: max-content;
  /* Opaque solid fill, no backdrop-filter (paints on the main layer).
     Crucially, the text colour is NOT set here: the bubble inherits the
     body's animating colour and carries NO colour transition of its own —
     exactly like the article paragraphs — so its text inverts in lockstep
     with the page on a theme toggle. Giving the bubble its own colour
     transition rode a separate timeline and lagged a beat behind. */
  background-color: rgb(250, 248, 242);
  border: none;
  border-radius: 16px;
  padding: 10px 15px;
  font-size: 0.84rem;
  line-height: 1.55;
  box-shadow: var(--glass-drop-pop), var(--glass-edge);
  opacity: 0;
  pointer-events: none;
  z-index: 4;                   /* over the settings bar while speaking */
  transition: opacity 0.3s var(--ease), transform 0.4s var(--ease-spring),
              background-color 0.3s var(--ease), box-shadow 0.3s var(--ease);
}
[data-theme="dark"] .mascot-bubble { background-color: rgb(48, 47, 43); }
.mascot-bubble.is-shown {
  opacity: 1;
  transform: translateY(0) scale(1);
}
/* little tail pointing down to the figure — matches the bubble fill so it
   inverts in step on a theme toggle. */
.mascot-bubble::after {
  content: '';
  position: absolute;
  left: 26px;
  bottom: -7px;
  width: 13px;
  height: 13px;
  background-color: rgb(250, 248, 242);
  border-bottom-right-radius: 3px;
  transform: rotate(45deg);
  transition: background-color 0.3s var(--ease);
}
[data-theme="dark"] .mascot-bubble::after { background-color: rgb(48, 47, 43); }
/* Near the top of the screen the bubble flips BELOW the figure so it
   isn't clipped; the tail then points up. */
.mascot.bubble-below .mascot-bubble {
  bottom: auto;
  top: 100%;
  margin-bottom: 0;
  margin-top: 4px;
  transform-origin: top left;
}
.mascot.bubble-below .mascot-bubble::after {
  bottom: auto;
  top: -7px;
  border-bottom-right-radius: 0;
  border-top-left-radius: 3px;
}
/* On the right side of the screen the bubble grows LEFTWARD so it isn't
   cut off; the tail moves to the right edge. */
.mascot.bubble-left .mascot-bubble {
  left: auto;
  right: 22px;
  transform-origin: bottom right;
}
.mascot.bubble-left.bubble-below .mascot-bubble { transform-origin: top right; }
.mascot.bubble-left .mascot-bubble::after {
  left: auto;
  right: 26px;
}

/* Tucked: after snapping to a side, the figure rests half off-screen;
   hovering or tapping makes it peek back out. */
/* Tucked idle uses a dedicated peek-left/right PNG, so keep it fully
   opaque (no dimming) — the art is designed to read at the edge. */
.mascot.is-tucked { opacity: 1; }
/* Left/right peek art isn't mirror-symmetric — the gripping hand sits at
   x≈178/400 on the left vs x≈215/400 on the right — so the left needs a
   slightly smaller shift to reveal the same amount of hand as the right. */
.mascot.is-tucked.tuck-left  { transform: translateX(-52%); }
.mascot.is-tucked.tuck-right { transform: translateX(54%); }
.mascot.is-tucked .mascot-settings,
.mascot.is-tucked .mascot-menu,
.mascot.is-tucked .mascot-bubble { opacity: 0 !important; pointer-events: none !important; }

/* ── Settings gear — a floating glass pill centred above the figure;
   hidden until the pointer nears, with a nav-tab sage tint + lift on
   hover. Hover-reveal logic continues below. */
.mascot-settings {
  position: absolute;
  bottom: 100%;
  left: 50%;
  transform: translateX(-50%);
  margin-bottom: 9px;
  display: inline-flex;
  align-items: center;
  justify-content: center;
  padding: 0;
  /* Golden-ratio bar: 48 / 30 ≈ 1.618 */
  width: 48px;
  height: 30px;
  background: var(--glass-bg);
  -webkit-backdrop-filter: var(--glass-blur);
  backdrop-filter: var(--glass-blur);
  color: var(--text-color);
  border: none;
  /* Full pill — same radius as the nav-bar tab buttons. */
  border-radius: 30px;
  cursor: pointer;
  box-shadow: var(--glass-drop), var(--glass-edge), inset 0 0 0 100px transparent;
  z-index: 2;
  /* Hidden by default — revealed when the pointer is near the figure. */
  opacity: 0;
  pointer-events: none;
  transform: translateX(-50%) translateY(4px);
  transition: opacity 0.25s var(--ease), transform 0.28s var(--ease-out),
              color 0.3s var(--ease), background 0.3s var(--ease), box-shadow 0.3s var(--ease);
}
/* Reveal when hovering the figure, on keyboard focus, or while the
   settings menu is open. */
.mascot:hover .mascot-settings,
.mascot:focus-within .mascot-settings,
.mascot-settings.is-active {
  opacity: 1;
  pointer-events: auto;
  transform: translateX(-50%) translateY(0);
}
/* The bar shares the space just above the figure with the speech
   bubble — so while a line is showing, tuck the bar away (it returns
   when the bubble clears). Keeps them from ever overlapping. */
.mascot:has(.mascot-bubble.is-shown) .mascot-settings {
  opacity: 0;
  transform: translateX(-50%) translateY(5px);
  pointer-events: none;
}
.mascot-settings svg { width: 15px; height: 15px; flex-shrink: 0; transition: transform 0.45s var(--ease-out); }
.mascot-settings.is-active svg { transform: rotate(90deg); }
/* Pointer on the button → soft sage tint and a lift, like the nav tabs. */
.mascot-settings:hover,
.mascot-settings.is-active {
  box-shadow: var(--glass-drop), var(--glass-edge), inset 0 0 0 100px var(--glass-tint);
  color: var(--accent-color);
  transform: translateX(-50%) translateY(-2px);
}
.mascot-settings:active {
  transform: translateX(-50%) translateY(-1px) scale(0.95);
  transition-duration: 0.08s;
}
/* Near the top of the screen the figure's "above" zone is off-screen,
   so the bar (and the menu below) drop BELOW the figure instead. */
.mascot.bubble-below .mascot-settings {
  bottom: auto;
  top: 100%;
  margin-bottom: 0;
  margin-top: 10px;
}

/* ── Settings popover — pops out beside the figure ─────────────────
   JS sets the inline left/top (which side + clamped to viewport); the
   side-* class drives the slide-out entrance from the figure's edge. */
.mascot-menu {
  position: absolute;
  left: 0;
  top: 0;
  width: max-content;
  min-width: 172px;
  background: var(--glass-panel);
  -webkit-backdrop-filter: var(--glass-blur);
  backdrop-filter: var(--glass-blur);
  border: none;
  border-radius: 16px;
  box-shadow: var(--glass-drop-pop), var(--glass-edge);
  padding: 7px;
  opacity: 0;
  transform: scale(0.96);
  pointer-events: none;
  transition: opacity 0.2s var(--ease), transform 0.32s var(--ease-spring),
              background 0.3s var(--ease), box-shadow 0.3s var(--ease);
  z-index: 5;                   /* above the speech bubble (z-4) when open */
}
/* Closed state slides in from whichever side it pops out of. */
.mascot-menu.side-right { transform: translateX(-12px) scale(0.96); transform-origin: left center; }
.mascot-menu.side-left  { transform: translateX(12px) scale(0.96); transform-origin: right center; }
.mascot-menu.is-open { opacity: 1; transform: none; pointer-events: auto; }
.mascot-menu .menu-title {
  font-size: 0.66rem;
  letter-spacing: 0.8px;
  color: var(--meta-color);
  padding: 6px 10px 4px;
  text-transform: uppercase;
}
.mascot-menu button {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 12px;
  width: 100%;
  background: none;
  border: none;
  border-radius: 9px;
  padding: 8px 11px;
  font-family: inherit;
  font-size: 0.85rem;
  color: var(--text-color);
  cursor: pointer;
  text-align: left;
  transition: background 0.18s var(--ease), color 0.18s var(--ease);
}
.mascot-menu button:hover { background: var(--btn-bg); }
.mascot-menu button[aria-pressed="true"] {
  background: var(--accent-bg);
  color: var(--accent-color);
  font-weight: 600;
}
.mascot-menu button[aria-pressed="true"]::after { content: '\2713'; font-size: 0.85em; }
.mascot-menu hr { border: none; border-top: 1px solid var(--border-color); margin: 6px 5px; }
.mascot-menu .menu-hide { color: var(--meta-color); }
/* Coral tint signals the "remove" action while the text stays the
   themed (readable) colour — coral is a mid-tone that fails AA as text. */
.mascot-menu .menu-hide:hover { color: var(--text-color); background: color-mix(in srgb, var(--persimmon) 16%, transparent); }

/* ── Dark-mode visibility on the (frosted) settings panel ──────────
   The glass is kept; only three elements that sat too close to the
   panel tone in dark mode are lifted:
   · "收起看板娘" used --meta-color (~4.1:1, under AA) → brighter warm grey;
   · the divider <hr> and the size-slider track used --border-color,
     which is almost the panel's own colour → redraw them with a faint
     light tint so they read against the glass.
   Light mode is untouched (it had enough contrast already). The slider
   track and its Firefox equivalent are split into separate rules: a
   vendor pseudo-element in a shared selector list voids the whole rule
   in non-Firefox browsers. */
[data-theme="dark"] .mascot-menu .menu-hide {
  color: #a8a59b;
}
[data-theme="dark"] .mascot-menu hr {
  border-top-color: color-mix(in srgb, var(--text-color) 40%, transparent);
}
[data-theme="dark"] .mascot-menu input[type="range"] {
  background: color-mix(in srgb, var(--text-color) 45%, transparent);
}
[data-theme="dark"] .mascot-menu input[type="range"]::-moz-range-track {
  background: color-mix(in srgb, var(--text-color) 45%, transparent);
}

/* Size slider — custom sage track + thumb to match the menu */
.mascot-menu input[type="range"] {
  -webkit-appearance: none;
  appearance: none;
  width: calc(100% - 16px);
  height: 4px;
  margin: 6px 8px 9px;
  border-radius: 3px;
  background: var(--border-color);
  cursor: pointer;
  accent-color: var(--accent-color);
}
.mascot-menu input[type="range"]::-webkit-slider-thumb {
  -webkit-appearance: none;
  appearance: none;
  width: 16px;
  height: 16px;
  border-radius: 50%;
  background: var(--accent-color);
  border: 2px solid var(--bg-color);
  box-shadow: 0 1px 4px rgba(0, 0, 0, 0.2);
  cursor: pointer;
}
.mascot-menu input[type="range"]::-moz-range-thumb {
  width: 16px;
  height: 16px;
  border: 2px solid var(--bg-color);
  border-radius: 50%;
  background: var(--accent-color);
  box-shadow: 0 1px 4px rgba(0, 0, 0, 0.2);
  cursor: pointer;
}
.mascot-menu input[type="range"]::-moz-range-track {
  height: 4px;
  border-radius: 3px;
  background: var(--border-color);
}

/* Collapsed re-open handle — back to its original shape: a small tab
   peeking from the left edge, now wearing the shared glass material. */
.mascot-reopen {
  position: fixed;
  left: 0;
  bottom: 16px;
  width: 46px;
  height: 46px;
  border-radius: 0 50% 50% 0;
  overflow: hidden;
  background: var(--glass-bg);
  -webkit-backdrop-filter: var(--glass-blur);
  backdrop-filter: var(--glass-blur);
  color: var(--text-color);
  border: none;
  cursor: pointer;
  z-index: 8;
  padding: 0;
  opacity: 0;
  transform: translateX(-100%);
  /* Snappy slide-in so it reads like a magnetic snap to the edge when it
     appears (matching the handle's own snap), not a slow fade. */
  transition: opacity 0.22s var(--ease), transform 0.2s var(--ease-out),
              color 0.3s var(--ease), background 0.3s var(--ease), box-shadow 0.3s var(--ease);
  box-shadow: var(--glass-drop), var(--glass-edge), inset 0 0 0 100px transparent;
  pointer-events: none;
}
.mascot-reopen.is-visible { opacity: 1; transform: translateX(0); pointer-events: auto; }
.mascot-reopen { display: flex; align-items: center; justify-content: center; }
.mascot-reopen svg {
  width: 20px;
  height: 20px;
  margin-left: 4px;            /* nudge off the clipped left edge */
  pointer-events: none;
  transition: color 0.3s var(--ease);
}
/* Pointer on the button → soft sage tint and a lift, like the nav tabs. */
.mascot-reopen:hover {
  box-shadow: var(--glass-drop), var(--glass-edge), inset 0 0 0 100px var(--glass-tint);
  color: var(--accent-color);
  transform: translateY(-2px);
}
.mascot-reopen:active {
  transform: scale(0.94);
  transition-duration: 0.08s;
}
/* The handle lands where the figure was hidden — mirror it to the right
   edge when the mascot left on that side. Vertical spot is set inline. */
.mascot-reopen.side-right {
  border-radius: 50% 0 0 50%;
  transform: translateX(100%);
}
.mascot-reopen.side-right.is-visible { transform: translateX(0); }
.mascot-reopen.side-right svg { margin-left: 0; margin-right: 4px; }
/* While dragged, the handle detaches from the edge into a full, freely
   moved disc (no edge clip), so repositioning it never looks broken. */
.mascot-reopen.is-grabbing {
  border-radius: 50%;
  transform: none;
  cursor: grabbing;
  box-shadow: var(--glass-drop-pop), var(--glass-edge);
}
.mascot-reopen.is-grabbing svg { margin: 0; }

@media (prefers-reduced-motion: reduce) {
  .mascot-img { animation: none; }
}
/* Compact on small screens (kept on mobile, just smaller) */
@media (max-width: 600px) {
  .mascot { width: 96px; left: 8px; }
  /* Responsive size guard: a scale saved on desktop is applied to the
     desktop base width via inline style, which can blow the figure up
     to ~40% of a phone screen and crowd the text. Cap it here — a
     stylesheet max-width overrides the non-!important inline width
     without touching the drag/resize JS. Default (96px) is unaffected. */
  .mascot { max-width: min(140px, 40vw) !important; }
  .mascot-bubble { max-width: 150px; font-size: 0.8rem; }
}

/* ── 404 page — the mascot's moment ────────────────────────────
   A centered hero: the chibi looking puzzled, a speech bubble, a big
   Garamond "404", and a quiet way home. The corner companion is
   suppressed here (its script bails when #error-404 is present) so
   this one is the star. */
.error-404 {
  text-align: center;
  padding: 30px 0 60px;
  display: flex;
  flex-direction: column;
  align-items: center;
}
.error-mascot {
  width: clamp(150px, 45vw, 220px);
  height: auto;
  filter: drop-shadow(0 10px 20px rgba(0, 0, 0, 0.14));
  animation: mascot-bob 4.5s ease-in-out infinite;
  user-select: none;
  -webkit-user-drag: none;
}
[data-theme="dark"] .error-mascot {
  filter: drop-shadow(0 10px 22px rgba(0, 0, 0, 0.5));
}
.error-bubble {
  position: relative;
  margin-top: 6px;
  background: var(--bg-color);
  color: var(--text-color);
  border: 1px solid var(--border-color);
  border-radius: 16px;
  padding: 10px 18px;
  font-size: 0.95rem;
  box-shadow: 0 4px 16px rgba(0, 0, 0, 0.08);
  transition: background 0.3s var(--ease), color 0.3s var(--ease), border-color 0.3s var(--ease);
}
.error-bubble::before {
  content: '';
  position: absolute;
  top: -7px;
  left: 50%;
  transform: translateX(-50%) rotate(45deg);
  width: 13px;
  height: 13px;
  background: var(--bg-color);
  border-left: 1px solid var(--border-color);
  border-top: 1px solid var(--border-color);
  transition: background 0.3s var(--ease), border-color 0.3s var(--ease);
}
.error-code {
  font-family: 'EB Garamond', serif;
  font-size: clamp(3.5rem, 18vw, 5rem);
  font-weight: 500;
  line-height: 1;
  letter-spacing: 2px;
  color: var(--accent-color);
  margin: 22px 0 24px;
  transition: color 0.3s var(--ease);
}
.error-home {
  margin-top: 0 !important;
}

/* ── Global reduced-motion guard ───────────────────────────────
   Honour the OS "reduce motion" setting site-wide: near-instant
   transitions/animations and no smooth-scroll. The same restraint
   Apple and Anthropic apply — motion is a finish, never a barrier. */
@media (prefers-reduced-motion: reduce) {
  *,
  *::before,
  *::after {
    animation-duration: 0.01ms !important;
    animation-iteration-count: 1 !important;
    transition-duration: 0.01ms !important;
    scroll-behavior: auto !important;
  }
}

/* ── Print ─────────────────────────────────────────────────────
   When an article is printed or saved to PDF, drop the interactive
   chrome (toggles, nav, pager, comments, margin rails, progress bar)
   and reset to black ink on white so the reading column prints clean
   and ink-frugal. Links show their URL for paper. */
@media print {
  .top-actions,
  nav.main-nav,
  .blog-pager,
  .comments-wrapper,
  .related-posts,
  .site-footer,
  .desktop-date-rail,
  .desktop-readtime-rail,
  .reading-bar,
  .reading-hint,
  .mascot,
  .mascot-reopen,
  .read-more {
    display: none !important;
  }
  body {
    background: #fff;
    color: #000;
  }
  .outer-wrapper {
    max-width: none;
    padding: 0;
  }
  .post-body img {
    box-shadow: none;
    border: 1px solid #ddd;
  }
  .post-body.full-content a {
    color: #000;
    text-decoration: underline;
  }
  .post-body.full-content a[href^="http"]::after {
    content: " (" attr(href) ")";
    font-size: 0.8em;
    color: #555;
    word-break: break-all;
  }
  .post-outer {
    page-break-inside: auto;
  }
  h2.post-title,
  .post-body.full-content h2,
  .post-body.full-content h3 {
    page-break-after: avoid;
  }
  .post-body.full-content img,
  .post-body.full-content blockquote,
  .post-body.full-content pre {
    page-break-inside: avoid;
  }
}

b:if.script:
//
window.addEventListener('DOMContentLoaded', () => {
  const list = document.getElementById('related-posts-list');
  const wrapper = document.querySelector('.related-posts');
  if (!list) return;

  const label = list.getAttribute('data-label');
  if (!label) {
    if (wrapper) wrapper.style.display = 'none';
    return;
  }

  const currentUrl = window.location.href.split(/[?#]/)[0];

  window.loadRelatedPosts = json => {
    let html = '';
    if (json && json.feed && json.feed.entry) {
      const posts = json.feed.entry;
      let count = 0;
      for (let i = 0; i < posts.length; i++) {
        const title = posts[i].title.$t;
        let url = '';
        for (let j = 0; j < posts[i].link.length; j++) {
          if (posts[i].link[j].rel === 'alternate') {
            url = posts[i].link[j].href;
            break;
          }
        }
        if (url.split(/[?#]/)[0] === currentUrl) continue;

        html += '<li><a href="' + url + '">' + title + '</a></li>';
        count++;
        if (count >= 3) break;
      }
    }
    if (html) {
      list.innerHTML = html;
    } else {
      if (wrapper) wrapper.style.display = 'none';
    }
  };

  const script = document.createElement('script');
  script.src = '/feeds/posts/default/-/' + encodeURIComponent(label) + '?alt=json-in-script&callback=loadRelatedPosts&max-results=6';
  document.body.appendChild(script);
});
//

div.script:
//
// Synchronous title wrap — runs during HTML parsing so titles render
// correctly on first paint with zero flash. Splits at CJK punctuation
// (and halfwidth colon for English subtitles), then wraps each phrase
// as inline-block;white-space:nowrap so the browser's only legal break
// point is BETWEEN phrases. Without this, greedy line-breaking puts
// the comma awkwardly mid-line (e.g. greedy fill packs 8 chars on
// the first line before breaking, instead of breaking at the comma).
(function() {
    const PUNCT = /(?<=[，。；！？：、:])/;
    const wrap = function(el) {
        if (!el) return;
        const parts = el.textContent.split(PUNCT).filter(Boolean);
        if (parts.length <= 1) return;
        el.innerHTML = '';
        parts.forEach(function(part) {
            const chunk = document.createElement('span');
            chunk.style.cssText = 'display:inline-block;white-space:nowrap;';
            chunk.textContent = part;
            el.appendChild(chunk);
        });
    };
    // Header site title
    wrap(document.querySelector('.header-logo-link > span'));
    // Post titles — list pages use <h2><a>...</a></h2>, single-post
    // pages render the title text directly inside <h2>
    document.querySelectorAll('h2.post-title').forEach(function(h2) {
        wrap(h2.querySelector('a') || h2);
    });
})();

// Active nav marker — purely presentational. Matches the current
// URL path against each nav link and tags the match with .is-active
// so you always know which section you're in. Runs synchronously
// (nav is already parsed above) for a flash-free first paint. Worst
// case it simply marks nothing — it can never break a page.
(function() {
    const nav = document.querySelector('nav.main-nav');
    if (!nav) return;
    const norm = function(p) { return (decodeURIComponent(p).replace(/\/+$/, '')) || '/'; };
    const here = norm(location.pathname);
    const links = nav.querySelectorAll('a');
    let active = null;
    links.forEach(function(a) {
        let p;
        try { p = norm(new URL(a.href, location.origin).pathname); } catch (e) { return; }
        if (p === here) active = a;
    });
    // Home link is the canonical match for the homepage path
    if (!active && here === '/' && links[0]) active = links[0];
    if (active) active.classList.add('is-active');
})();

// Nav overflow detection — toggle scroll mode only when labels
// actually overflow the container. ResizeObserver covers window
// resize, font-load reflows, and the lang/variant toggles that
// change individual button widths. The CSS default is visible
// overflow so hover lift never gets clipped in the common case.
(function() {
    const nav = document.querySelector('nav.main-nav');
    if (!nav) return;
    const check = function() {
        nav.classList.toggle('is-scrolling', nav.scrollWidth > nav.clientWidth + 1);
    };
    check();
    if ('ResizeObserver' in window) {
        new ResizeObserver(check).observe(nav);
    } else {
        window.addEventListener('resize', check);
    }

    // Mouse-wheel horizontal scroll. Browsers don't auto-translate
    // vertical wheel into horizontal scroll, so mouse users would be
    // stuck unable to scroll an overflowing nav (touchpad users can
    // 2-finger swipe; touch users can drag). We redirect the wheel
    // delta only when:
    //   1. The nav is actually in scroll mode (else let page scroll)
    //   2. Vertical wheel dominates horizontal (user spun the wheel)
    //   3. There's actual scrollable distance in that direction
    // Otherwise the event passes through to the page's natural scroll.
    nav.addEventListener('wheel', function(e) {
        if (!nav.classList.contains('is-scrolling')) return;
        if (Math.abs(e.deltaY) <= Math.abs(e.deltaX)) return;
        const dir = e.deltaY > 0 ? 1 : -1;
        const atEnd = (dir > 0 && nav.scrollLeft >= nav.scrollWidth - nav.clientWidth - 1) ||
                    (dir < 0 && nav.scrollLeft <= 0);
        if (atEnd) return;
        e.preventDefault();
        nav.scrollLeft += e.deltaY;
    }, { passive: false });
})();

// Desktop margin rails — date (left) + read time (right).
// Single-post view, viewport >=1024px. The rails form a symmetric
// pair of margin notes flanking the reading column; pure decoration
// that doesn't interfere with the reading flow.
(function() {
    if (window.innerWidth < 1024) return;
    const postBody = document.querySelector('.post-body.full-content');
    if (!postBody) return;

    // ── Date parser ────────────────────────────────────────────────
    // Try three sources in reliability order: inline .post-meta text,
    // sibling .date-header element, or the YYYY/MM URL segment.
    const parseDate = function() {
        const meta = document.querySelector('.post-meta');
        if (meta) {
            for (let i = 0; i < meta.childNodes.length; i++) {
                const n = meta.childNodes[i];
                if (n.nodeType === 3 && n.textContent.trim()) {
                    const d = new Date(n.textContent.trim());
                    if (!isNaN(d.getTime())) return d;
                    break;
                }
            }
        }
        const sibling = document.querySelector('.date-header');
        if (sibling) {
            const ds = new Date(sibling.textContent.trim());
            if (!isNaN(ds.getTime())) return ds;
        }
        const m = window.location.pathname.match(/\/(\d{4})\/(\d{2})\//);
        if (m) return new Date(parseInt(m[1], 10), parseInt(m[2], 10) - 1, 1);
        return null;
    };

    // ── Reading-time estimator ─────────────────────────────────────
    // Chinese: ~350 cpm (compact, no spaces). English: ~220 wpm.
    // Mixed content gets a proportional blend. Floor at 1 minute.
    const estimateReadMinutes = function(text) {
        if (!text) return 1;
        const cjk = (text.match(/[\u4e00-\u9fff]/g) || []).length;
        // Strip CJK then count word-like runs for the English portion
        const noCjk = text.replace(/[\u4e00-\u9fff]/g, ' ');
        const enWords = (noCjk.match(/[A-Za-z0-9]+/g) || []).length;
        const minutes = cjk / 350 + enWords / 220;
        return Math.max(1, Math.round(minutes));
    };

    // ── Date display strings ───────────────────────────────────────
    // English: "MAY · 2026" — small caps with tracking, horizontal.
    // Chinese: fullwidth-digit year + zh month name, vertical (set in CSS).
    const EN_MONTHS = ['JANUARY','FEBRUARY','MARCH','APRIL','MAY','JUNE',
                     'JULY','AUGUST','SEPTEMBER','OCTOBER','NOVEMBER','DECEMBER'];
    const ZH_MONTHS = ['一月','二月','三月','四月','五月','六月',
                     '七月','八月','九月','十月','十一月','十二月'];
    const ZH_DIGITS = ['〇','一','二','三','四','五','六','七','八','九'];
    const toZhYear = function(year) {
        return String(year).split('').map(function(d) {
            return ZH_DIGITS[parseInt(d, 10)];
        }).join('');
    };
    const toZhMinutes = function(n) {
        // Up to 99 minutes — beyond that we render Arabic digits
        // (a 100-minute reading time is unrealistic for a blog post).
        if (n < 10) return ZH_DIGITS[n];
        if (n >= 100) return String(n);
        const tens = Math.floor(n / 10);
        const ones = n % 10;
        const tensStr = tens === 1 ? '十' : ZH_DIGITS[tens] + '十';
        return ones === 0 ? tensStr : tensStr + ZH_DIGITS[ones];
    };

    const rails = [];

    // Left rail: date
    const d = parseDate();
    if (d) {
        const dateRail = document.createElement('div');
        dateRail.className = 'desktop-date-rail';
        dateRail.setAttribute('aria-hidden', 'true');
        dateRail.innerHTML =
            '<span class="lang-zh">' + toZhYear(d.getFullYear()) + '·' + ZH_MONTHS[d.getMonth()] + '</span>' +
            '<span class="lang-en">' + EN_MONTHS[d.getMonth()] + ' · ' + d.getFullYear() + '</span>';
        document.body.appendChild(dateRail);
        rails.push(dateRail);
    }

    // Right rail: read time
    const minutes = estimateReadMinutes(postBody.textContent || '');
    const rtRail = document.createElement('div');
    rtRail.className = 'desktop-readtime-rail';
    rtRail.setAttribute('aria-hidden', 'true');
    rtRail.innerHTML =
        '<span class="lang-zh">约 ' + toZhMinutes(minutes) + ' 分钟</span>' +
        '<span class="lang-en">' + minutes + ' MIN READ</span>';
    document.body.appendChild(rtRail);
    rails.push(rtRail);

    // Fade in both rails together one frame later, so they appear
    // as a synchronized pair after the page settles
    requestAnimationFrame(function() {
        rails.forEach(function(el) { el.classList.add('is-ready'); });
    });
})();

// Reading-progress bar + tap-to-top — single-post view only.
// A thin sage line pinned to the bottom edge fills as the reader
// descends; the whole strip (taller invisible hit area) is tappable
// to glide back to the top. A small bilingual hint teaches the
// gesture when the bar first appears and again at completion, then
// auto-fades; hovering the bar also reveals it.
(function() {
    const articleBody = document.querySelector('.post-body.full-content');
    if (!articleBody) return;

    const bar = document.createElement('div');
    bar.className = 'reading-bar';
    bar.setAttribute('role', 'button');
    bar.setAttribute('tabindex', '0');
    bar.setAttribute('aria-label', 'Back to top');
    const fill = document.createElement('div');
    fill.className = 'bar-fill';
    bar.appendChild(fill);
    document.body.appendChild(bar);

    // Bilingual hint pill — the lang spans are shown/hidden by the
    // existing [data-lang] rules, so it tracks the language toggle.
    const hint = document.createElement('div');
    hint.className = 'reading-hint';
    hint.setAttribute('aria-hidden', 'true');
    hint.innerHTML =
        '<span class="hint-arrow" aria-hidden="true">↑</span>' +
        '<span class="lang-zh">点击返回顶部</span>' +
        '<span class="lang-en">Tap to return to the top</span>';
    document.body.appendChild(hint);

    const reduceMotion = function() {
        return window.matchMedia('(prefers-reduced-motion: reduce)').matches;
    };
    const toTop = function() {
        window.scrollTo({ top: 0, behavior: reduceMotion() ? 'auto' : 'smooth' });
    };
    bar.addEventListener('click', toTop);
    bar.addEventListener('keydown', function(e) {
        if (e.key === 'Enter' || e.key === ' ') { e.preventDefault(); toTop(); }
    });

    // Show the hint; if a duration is given, auto-hide after it.
    let hideTimer = null;
    const showHint = function(duration) {
        hint.classList.add('is-shown');
        if (hideTimer) { clearTimeout(hideTimer); hideTimer = null; }
        if (duration) hideTimer = setTimeout(function() {
            hint.classList.remove('is-shown');
        }, duration);
    };
    const hideHint = function() {
        if (hideTimer) { clearTimeout(hideTimer); hideTimer = null; }
        hint.classList.remove('is-shown');
    };
    // Desktop: reveal while the pointer is over the bar, fade out
    // as soon as it leaves.
    bar.addEventListener('mouseenter', function() { showHint(0); });
    bar.addEventListener('mouseleave', function() { hideHint(); });

    let appeared = false;
    let completedHinted = false;
    let ticking = false;
    // Cache the article's document-bottom so the per-frame scroll
    // handler never forces a layout read. Progress is measured against
    // the END OF THE ARTICLE BODY (not the page), so it hits 100% as the
    // last line reaches the viewport bottom, before comments/footer.
    // Re-measure only when the article actually resizes (images loading)
    // or the window resizes — not on every scroll tick.
    let articleDocBottom = 0;
    const measureArticle = function() {
        articleDocBottom = articleBody.getBoundingClientRect().bottom +
            (window.scrollY || document.documentElement.scrollTop);
    };
    measureArticle();
    if ('ResizeObserver' in window) new ResizeObserver(measureArticle).observe(articleBody);
    window.addEventListener('load', measureArticle);
    const update = function() {
        ticking = false;
        const scrollTop = window.scrollY || document.documentElement.scrollTop;
        const target = Math.max(1, articleDocBottom - window.innerHeight);
        const pct = Math.min(1, Math.max(0, scrollTop / target));
        fill.style.transform = 'scaleX(' + pct.toFixed(4) + ')';

        const active = scrollTop > window.innerHeight * 0.6;
        bar.classList.toggle('is-active', active);

        // Teach the gesture the first time the bar appears…
        if (active && !appeared) {
            appeared = true;
            showHint(2000);
        }
        // …and nudge once more when the reader reaches the end.
        if (pct > 0.985 && !completedHinted) {
            completedHinted = true;
            showHint(2000);
        }
        // Tuck the hint away if we're back at the very top.
        if (!active) hideHint();
    };
    const onScroll = function() {
        if (!ticking) {
            requestAnimationFrame(update);
            ticking = true;
        }
    };
    window.addEventListener('scroll', onScroll, { passive: true });
    window.addEventListener('resize', function() { measureArticle(); onScroll(); }, { passive: true });
    update();
})();

// ── Mascot ──────────────────────────────────────────────────────
// A chibi corner companion: greets by time of day, reacts to page
// events (copy, nav hover, article end, theme toggle), murmurs when
// idle, changes expression on click. Art loads on demand and the whole
// thing self-removes if it can't load (no broken images). Lines follow
// the language toggle.
(function() {
    // The 404 page already shows the mascot as its hero — skip here.
    if (document.getElementById('error-404')) return;

    // Where the mascot PNGs live (jsDelivr → blog-assets repo).
    var BASE = 'https://cdn.jsdelivr.net/gh/rinuuan/blog-assets@main/mascot/chibi';
    var HIDE_KEY = 'mascotHidden';
    // Chatter level: 'full' (lively), 'less' (only key moments),
    // 'mute' (figure stays, but silent). Remembered across visits.
    var CHAT_KEY = 'mascotChat';
    var chatLevel = 'full';
    try { chatLevel = localStorage.getItem(CHAT_KEY) || 'full'; } catch (e) {}
    var ambient = function() { return chatLevel === 'full'; };
    // Stepless size: a scale factor (0.6–1.6) over the per-viewport
    // base width, remembered across visits.
    var SIZE_KEY = 'mascotScale';
    var mascotScale = 1;
    try { var sv = parseFloat(localStorage.getItem(SIZE_KEY)); if (sv) mascotScale = Math.min(1.6, Math.max(0.6, sv)); } catch (e) {}

    var wrap = document.createElement('div');
    wrap.className = 'mascot';
    // The <img> starts srcless — the PNG is fetched only when the mascot
    // is shown (see boot/show), so it never blocks first paint and costs
    // nothing for visitors who've dismissed it.
    var L = function(zh, en) { return '<span class="lang-zh">' + zh + '</span><span class="lang-en">' + en + '</span>'; };
    wrap.innerHTML =
        '<button class="mascot-settings" type="button" aria-haspopup="true" aria-expanded="false" aria-label="看板娘设置 / Mascot settings">' +
          '<svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.7" ' +
          'stroke-linecap="round" stroke-linejoin="round" aria-hidden="true">' +
            '<circle cx="12" cy="12" r="3"/>' +
