          '</svg>' +
        '</button>' +
        '<div class="mascot-menu" role="group" aria-label="看板娘设置 / Mascot settings">' +
          '<div class="menu-title">' + L('台词', 'Chatter') + '</div>' +
          '<button type="button" data-level="full">' + L('活泼', 'Lively') + '</button>' +
          '<button type="button" data-level="less">' + L('少话', 'Quiet') + '</button>' +
          '<button type="button" data-level="mute">' + L('静音', 'Mute') + '</button>' +
          '<hr/>' +
          '<div class="menu-title">' + L('大小', 'Size') + '</div>' +
          '<input type="range" class="mascot-size" min="0.6" max="1.6" step="0.02" aria-label="看板娘大小 / Mascot size"/>' +
