        '<img class="mascot-img" alt="Site mascot" draggable="false" decoding="async" width="1024" height="1536"/>';
    document.body.appendChild(wrap);

    // Re-open handle — a light inline icon, no image to download.
    var reopen = document.createElement('button');
    reopen.className = 'mascot-reopen';
    reopen.type = 'button';
    reopen.setAttribute('aria-label', '显示看板娘 / Show mascot');
    reopen.innerHTML =
        '<svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.8" ' +
        'stroke-linecap="round" stroke-linejoin="round" aria-hidden="true">' +
          '<path d="M21 11.5a8.38 8.38 0 0 1-8.5 8.5 8.38 8.38 0 0 1-3.8-.9L3 21l1.9-5.7A8.38 8.38 0 0 1 4 11.5 8.5 8.5 0 0 1 12.5 3 8.38 8.38 0 0 1 21 11.5z"/>' +
        '</svg>';
    document.body.appendChild(reopen);

    var imgEl = wrap.querySelector('.mascot-img');
    var bubble = wrap.querySelector('.mascot-bubble');
    var textEl = wrap.querySelector('.mascot-text');

    // If the displayed art fails to load, retry once before giving up.
    // jsDelivr occasionally returns a transient 503, and a hard removal
    // on a flaky response would kill the mascot for the whole session.
    // Only after the retry also fails do we remove everything (still
    // never a broken image). A successful load resets the flag, so a
    // later, unrelated failure gets its own single retry.
    var imgRetried = false;
    imgEl.addEventListener('load', function() { imgRetried = false; });
    imgEl.onerror = function() {
        var src = imgEl.getAttribute('src');
        if (!imgRetried && src) {
            imgRetried = true;
            imgEl.removeAttribute('src');   // drop the broken state (no request, no error)
            // Re-request after a beat — but only if nothing else has
            // since set a src (e.g. the user woke a mood mid-retry), so
            // the retry can't clobber a newer, good image.
            setTimeout(function() {
                if (!imgEl.getAttribute('src')) imgEl.src = src;
            }, 800);
            return;
        }
        wrap.remove(); reopen.remove();
    };
    var ensureLoaded = function() {
        if (!imgEl.getAttribute('src')) imgEl.src = BASE + '/happy.png';
    };

    var lang = function() {
        return document.documentElement.getAttribute('data-lang') === 'en' ? 'en' : 'zh';
    };
    // Follow the simplified/traditional toggle. Lines are stored in
    // simplified; in Traditional mode convert them with the same OpenCC
    // the theme already loads. (A bubble already on screen when the user
    // toggles is converted by the theme's whole-body pass.)
    var s2tConverter = null;
    var toVariant = function(text) {
        if (document.documentElement.getAttribute('data-variant') === 'trad' && window.OpenCC) {
            try {
                if (!s2tConverter) s2tConverter = window.OpenCC.Converter({ from: 'cn', to: 'tw' });
                return s2tConverter(text);
            } catch (e) {}
        }
        return text;
    };

    // Generic flicker-free art swap, shared by the normal expressions
    // and the edge-peek poses: preload, then assign. A monotonically
    // increasing token guards against load races — if the visitor
    // wakes the figure while a peek image is still in flight, the stale
    // onload is ignored so it can't clobber the restored expression.
    var loaded = { happy: true };
    var artToken = 0;
    var setArt = function(name, isPeek) {
        var url = BASE + '/' + name + '.png';
        var token = ++artToken;
        if (loaded[name]) { imgEl.src = url; return; }
        var pre = new Image();
        pre.onload = function() {
            loaded[name] = true;
            if (token === artToken) imgEl.src = url;   // only the latest request wins
        };
        // A missing peek image must never tear down the whole mascot —
        // fall back to the last expression instead. Normal expressions
        // keep the existing failure handling (imgEl.onerror removes all).
        if (isPeek) {
            pre.onerror = function() {
                if (token === artToken) setArt(currentMood, false);
            };
        }
        pre.src = url;
    };
    // Remember the last normal expression so we can return to it after
    // a peek, and so a failed peek load has something to fall back to.
    var currentMood = 'happy';
    var setMood = function(mood) {
        currentMood = mood;
        setArt(mood, false);
    };
    // Warm a side's peek pose so the first tuck is instant. Called
    // lazily (only once a tuck is actually scheduled, see scheduleTuck)
    // so dismissed visitors and desktop visitors who never tuck don't
    // pay for art they'll never see. Fetched once per side.
    var peekWarmed = {};
    var warmPeek = function(side) {
        var name = 'peek-' + side;
        if (peekWarmed[name]) return;
        peekWarmed[name] = true;
        var pre = new Image();
        pre.onload = function() { loaded[name] = true; };
        pre.src = BASE + '/' + name + '.png';
    };

    // Idle is declared up here (hoisted) so say() can reset it.
    var idleTimer = null;
    function resetIdle() {
        if (idleTimer) clearTimeout(idleTimer);
        // Randomised 1–2 min gap so the idle chatter feels natural,
        // not like clockwork nagging.
        idleTimer = setTimeout(function() { if (ambient()) sayMoods(IDLE_MOODS); }, 60000 + Math.random() * 60000);
    }

    var bubbleTimer = null;
    var say = function(line, hold, force) {
        if (!line) return;
        if (wrap.classList.contains('is-hidden')) return;   // dismissed → stay quiet
        if (chatLevel === 'mute' && !force) return;          // muted → only forced feedback
        if (tucked) untuck();                 // peek out to speak
        setMood(line.mood);
        var txt = line[lang()] || line.zh;
        textEl.textContent = lang() === 'zh' ? toVariant(txt) : txt;
        if (updateBubbleSide) updateBubbleSide();
