        bubbleTimer = setTimeout(function() { bubble.classList.remove('is-shown'); }, hold || 4800);
        resetIdle();
        // Don't tuck away mid-sentence — push the tuck past this line.
        if (scheduleTuck) scheduleTuck();
    };
