        var l;
        do { l = a[Math.floor(Math.random() * a.length)]; } while (l === lastLine);
        lastLine = l;
        return l;
    };

    // Show a random line from a mood's pool, tagged with that mood.
    var sayMoods = function(moodArr) {
        var m = moodArr[Math.floor(Math.random() * moodArr.length)];
        var l = pick(MOODS[m]);
        say({ mood: m, zh: l.zh, en: l.en });
    };
    // Which expressions each "draw from the pools" scenario may use.
    var CLICK_MOODS = ['surprised', 'angry', 'shy', 'excited', 'happy', 'confused'];
    var IDLE_MOODS = ['sleepy', 'sad', 'confused', 'shy'];

