        ],
        noon: [
            { mood: 'happy',     zh: '中午啦，别假装很忙，快去吃饭！', en: 'Noon already — stop pretending to be busy, go eat!' },
            { mood: 'surprised', zh: '诶，已经晌午了？时间好快！',     en: 'Huh, midday already? Time flies!' },
            { mood: 'confused',  zh: '午饭…吃了没？我有点记不清。',   en: 'Lunch… did you eat? I lost track.' }
        ],
        afternoon: [
            { mood: 'excited', zh: '下午好~ 是不是又在摸鱼呀？',   en: 'Afternoon~ slacking off again, are we?' },
            { mood: 'sleepy',  zh: '下午最容易犯困，要不要小憩？', en: 'Afternoons make me drowsy — a little nap?' },
            { mood: 'happy',    zh: '午后慢悠悠，最适合闲逛啦。',   en: 'Lazy afternoons are perfect for a wander.' }
        ],
        evening: [
            { mood: 'shy',    zh: '晚上好，夜猫子说的就是你吧？', en: 'Evening — night owl, that’s you, isn’t it?' },
            { mood: 'happy',  zh: '忙完一天啦？晚上好好放松~',   en: 'Done for the day? Relax this evening~' },
            { mood: 'sleepy', zh: '夜色温柔，灯也暖暖的呢。',     en: 'The night’s gentle, the lights all warm.' }
        ],
        night: [
            { mood: 'sleepy', zh: '这么晚还不睡？我可要先困了哦…', en: 'Still up this late? I’m dozing off first…' },
            { mood: 'shy',    zh: '夜深人静…只剩我们俩了呢。',     en: 'Late and quiet… just the two of us now.' },
            { mood: 'sad',    zh: '熬夜对身体不好啦，早点歇息嘛。', en: 'Late nights aren’t kind to you — do rest soon.' }
        ]
    };
    var WELCOME = [
        { mood: 'excited', zh: '初次见面~ 我是这儿的看板娘，请多关照！', en: 'First time here? I’m the resident mascot — pleased to meet you!' },
        { mood: 'shy',     zh: '欢、欢迎光临…我会陪着你逛的。',       en: 'W-welcome… I’ll keep you company as you look around.' }
    ];
    var THEME = {
        dark: [
            { mood: 'sleepy',    zh: '啪——关灯！夜读模式，护眼哦。', en: 'Click — lights out! Easy on the eyes now.' },
            { mood: 'shy',       zh: '暗下来了…黑黑的有点安心呢。',   en: 'It’s dim now… the dark feels rather cozy.' },
            { mood: 'surprised', zh: '哇，突然变暗，吓我一跳！',       en: 'Whoa, sudden dark — that startled me!' }
        ],
        light: [
            { mood: 'excited',   zh: '啪！开灯，世界亮晶晶~',     en: 'Snap! Lights on — sparkly world~' },
            { mood: 'happy',     zh: '亮堂堂的，心情都跟着好啦！', en: 'All bright now — my mood lit right up!' },
            { mood: 'surprised', zh: '唔！好刺眼，等我适应一下…',   en: 'Ngh! So bright — let me adjust…' }
        ]
    };
    var COPY = [
        { mood: 'surprised', zh: '哦？偷偷复制，被我抓到啦！',   en: 'Oho — sneaky copy-pasting, caught you!' },
        { mood: 'excited',   zh: '这句好用对吧？拿去拿去~',     en: 'Good line, right? Take it, take it~' },
        { mood: 'shy',       zh: '被你选中的句子…会害羞的。',   en: 'The line you picked… it’s blushing.' },
        { mood: 'happy',     zh: '喜欢就抄走吧，记得标出处哦。', en: 'Copy away if you like it — just credit it~' }
    ];
    var NAV = [
        { mood: 'excited',  zh: '想去哪儿呀？我跟着你~',     en: 'Where are we off to? I’ll tag along~' },
        { mood: 'happy',    zh: '挑个喜欢的地方逛逛吧。',     en: 'Pick a spot you fancy and let’s wander.' },
        { mood: 'confused', zh: '挑花眼了吗？慢慢来，不急。', en: 'Spoiled for choice? Take your time.' }
    ];
    var END = [
        { mood: 'excited',   zh: '哇，居然全看完了，给你比个心！', en: 'Whoa, you read it all — here’s a heart!' },
        { mood: 'happy',     zh: '看完啦，要不要再翻一篇？',     en: 'All done — fancy another one?' },
        { mood: 'surprised', zh: '诶？这就到底了，意犹未尽吧~',   en: 'Huh, the end already? Wanting more, hmm?' },
        { mood: 'shy',       zh: '谢谢你…读到了最后呢。',       en: 'Thank you… for reading to the very end.' }
    ];
    // Sent home by a double-tap.
    var HOME = [
        { mood: 'happy',   zh: '回到老位置~ 这里最舒服啦！', en: 'Back to my usual spot~ comfiest here!' },
        { mood: 'excited', zh: '嗖——回家咯！',             en: 'Whoosh — back home!' }
    ];
    // Halfway through an article.
    var HALF = [
        { mood: 'happy',    zh: '读到一半啦，我可一直盯着没走神~', en: 'Halfway! I’ve been watching the whole time, no spacing out~' },
        { mood: 'excited',  zh: '精彩的地方快来了吧？我也好奇！', en: 'The good part’s coming, right? I’m curious too!' },
        { mood: 'shy',      zh: '陪你读到这里…有点小满足。',   en: 'Reading this far with you… quietly satisfying.' },
        { mood: 'confused', zh: '唔，前面讲到哪儿了来着？',     en: 'Um, what was it about so far again?' }
    ];
    // Been on the page a long while.
    var LONGSTAY = [
        { mood: 'shy',     zh: '已经陪你这么久啦…有点开心呢。', en: 'We’ve been together a while now… quietly happy.' },
        { mood: 'happy',   zh: '时间过得真快，看得入迷了吧？',   en: 'Time flies — really absorbed, aren’t you?' },
        { mood: 'sleepy',  zh: '陪你这么久，我都快长屏幕上啦~',   en: 'I’ve been with you so long I’m basically part of the screen~' },
        { mood: 'excited', zh: '你是我今天最久的伙伴啦！',       en: 'You’re my longest-staying friend today!' }
    ];
    // Scrolled back near the top after going deep.
    var BACKTOP = [
        { mood: 'happy',     zh: '又回到开头啦，再读一遍？',   en: 'Back at the top — another read?' },
        { mood: 'excited',   zh: '嗖地飞回来了，好快！',       en: 'Whoosh, flew right back — so fast!' },
        { mood: 'surprised', zh: '诶，一下子回顶了？',         en: 'Huh, back to the top in a blink?' }
    ];
    // Came back to the tab after being away.
    var RETURN = [
        { mood: 'excited',   zh: '你回来啦！想我没~',         en: 'You’re back! Did you miss me~' },
        { mood: 'happy',     zh: '欢迎回来~ 位子给你留着呢。', en: 'Welcome back~ I saved your seat.' },
        { mood: 'surprised', zh: '诶，刚刚去哪儿啦？',         en: 'Huh, where’d you slip off to?' },
        { mood: 'shy',       zh: '刚刚…有点想你了呢。',       en: 'Just now… I missed you a little.' }
    ];
    // Per-label greetings — each label gets a spread of expressions;
    // add your own, keyed by the label name. Labels without an entry
    // fall back to LABEL_DEFAULT, so every label page is covered.
    var LABEL_LINES = {
        '中文': [
            { mood: 'happy',   zh: '中文专区~ 慢慢读，别噎着。',   en: 'The Chinese corner~ read slowly, don’t choke.' },
            { mood: 'excited', zh: '方块字真好看，对吧！',         en: 'Aren’t these square characters lovely!' },
            { mood: 'shy',     zh: '我的中文…还在偷偷练呢。',     en: 'My Chinese… still secretly practising.' }
        ],
        'English': [
            { mood: 'excited',  zh: 'English time！我的口语也在偷偷练哦~', en: 'English time! I’ve been practising too~' },
            { mood: 'happy',    zh: '换个语言换个心情，走起！',         en: 'New language, new mood — let’s go!' },
            { mood: 'confused', zh: '唔…这个词怎么念来着？',           en: 'Um… how do you pronounce this one again?' }
        ]
    };
    var LABEL_DEFAULT = [
        { mood: 'excited',  zh: '这个话题我也想多看看，一起呀！', en: 'I want to dig into this one too — together!' },
        { mood: 'happy',    zh: '挑了个有意思的角落呢。',         en: 'You picked an interesting little corner.' },
        { mood: 'confused', zh: '这个分类…我也有点好奇呢。',       en: 'This category… I’m a bit curious too.' }
    ];

    // First-time welcome, then label-aware, then time-of-day greeting.
    var SEEN_KEY = 'mascotSeen';
    var currentLabel = function() {
        var m = decodeURIComponent(location.pathname).match(/\/search\/label\/(.+?)\/?$/);
        return m ? m[1] : null;
    };
    var timeKey = function() {
        var h = new Date().getHours();
        return h < 5 ? 'night' : h < 11 ? 'morning' : h < 14 ? 'noon' : h < 18 ? 'afternoon' : h < 22 ? 'evening' : 'night';
    };
    var greet = function() {
        var first = false;
        try { first = !localStorage.getItem(SEEN_KEY); if (first) localStorage.setItem(SEEN_KEY, '1'); } catch (e) {}
        if (first) { say(pick(WELCOME), 6000); return; }
        var lbl = currentLabel();
        if (lbl) { say(pick(LABEL_LINES[lbl] || LABEL_DEFAULT), 5500); return; }
        say(pick(GREET[timeKey()]), 5500);
    };

    // Interactions
    document.addEventListener('copy', function() { say(pick(COPY)); });

    // Hover the figure to keep the current line up long enough to
    // read; let it fade shortly after the pointer leaves.
    imgEl.addEventListener('mouseenter', function() {
        if (bubbleTimer) { clearTimeout(bubbleTimer); bubbleTimer = null; }
        // Peek fully out while hovered, and don't tuck back until leave.
        if (tucked) setArt(currentMood, false);   // restore the real face first
        wrap.classList.remove('is-tucked');
        tucked = false;
        if (tuckTimer) { clearTimeout(tuckTimer); tuckTimer = null; }
    });
    imgEl.addEventListener('mouseleave', function() {
        if (bubble.classList.contains('is-shown')) {
            if (bubbleTimer) clearTimeout(bubbleTimer);
            bubbleTimer = setTimeout(function() { bubble.classList.remove('is-shown'); }, 1600);
        }
        scheduleTuck();
    });

    // ── Drag to reposition (remembered) + tap to react ─────────
    var POS_KEY = 'mascotPos';
    var dragging = false, moved = false, sx = 0, sy = 0, baseLeft = 0, baseTop = 0;
    var snapSide = null, tucked = false, tuckTimer = null;
    var TUCK_DELAY = 7000;   // longer than any bubble hold, so it never tucks mid-line
    // Flip the bubble below the figure when it's too near the top.
    // top/centerX may be passed in (e.g. during a drag) to avoid a
    // layout read; otherwise they're measured.
    var updateBubbleSide = function(top, centerX) {
        if (top === undefined) {
            var r = wrap.getBoundingClientRect();
            top = r.top; centerX = r.left + r.width / 2;
        }
        wrap.classList.toggle('bubble-below', top < 96);
        // On the right portion of the screen, grow the popovers
        // leftward so they aren't cut off by the edge.
        wrap.classList.toggle('bubble-left', centerX > window.innerWidth * 0.6);
    };
    // After it's snapped to a side, tuck it half off-screen when idle.
    var scheduleTuck = function() {
        if (tuckTimer) { clearTimeout(tuckTimer); tuckTimer = null; }
        if (!snapSide) return;
        warmPeek(snapSide);   // fetch this side's peek art ahead of the tuck
        tuckTimer = setTimeout(function() {
            if (snapSide) {
                // Switch to the side-specific peek pose, then tuck.
                setArt(snapSide === 'left' ? 'peek-left' : 'peek-right', true);
                wrap.classList.add('is-tucked');
                tucked = true;
            }
        }, TUCK_DELAY);
    };
    var untuck = function() {
        if (tucked) setArt(currentMood, false);   // peek → restore the real face
        wrap.classList.remove('is-tucked');
        tucked = false;
        scheduleTuck();
    };
    var clampPos = function(l, t) {
        var w = wrap.offsetWidth || 140, h = wrap.offsetHeight || 200;
        return {
            left: Math.max(4, Math.min(window.innerWidth - w - 4, l)),
            top:  Math.max(4, Math.min(window.innerHeight - h - 4, t))
        };
    };
    var applyPos = function(l, t) {
        wrap.style.left = l + 'px';
        wrap.style.top = t + 'px';
        wrap.style.bottom = 'auto';
    };
    // Looser clamp used WHILE dragging: lets the figure go mostly past an
    // edge (keeping a 24px sliver on-screen) so it can be dragged off to
    // hide. The strict clampPos still governs resting/snapped positions.
    var dragClamp = function(l, t) {
        var w = wrap.offsetWidth || 140, h = wrap.offsetHeight || 200, edge = 24;
        return {
            left: Math.max(-(w - edge), Math.min(window.innerWidth - edge, l)),
            top:  Math.max(-(h - edge), Math.min(window.innerHeight - edge, t))
        };
    };
    var baseW = function() { return window.innerWidth <= 600 ? 96 : 172; };
    var applySize = function() { wrap.style.width = Math.round(baseW() * mascotScale) + 'px'; };
    applySize();
    var savePos = function(l, t) {
        try { localStorage.setItem(POS_KEY, JSON.stringify({ left: l, top: t })); } catch (e) {}
    };
    var restorePos = function() {
        try {
            var p = JSON.parse(localStorage.getItem(POS_KEY));
            if (p && typeof p.left === 'number') {
                var c = clampPos(p.left, p.top); applyPos(c.left, c.top);
                // Remember which side it was on, and let it tuck when idle.
                var toLeft = (c.left + (wrap.offsetWidth || 140) / 2) < window.innerWidth / 2;
                snapSide = toLeft ? 'left' : 'right';
                wrap.classList.add(toLeft ? 'tuck-left' : 'tuck-right');
                scheduleTuck();
            }
        } catch (e) {}
    };
    // Timer for the snap transition, so a new gesture can cancel one
    // still in flight.
    var motionTimer = null;
    var cancelMotion = function() {
        if (motionTimer) { clearTimeout(motionTimer); motionTimer = null; }
    };
    // On release, snap to the nearest edge and remember the side. Short
    // plain glide, no inertia — it stays on the side it was let go on.
    var snapToEdge = function() {
        cancelMotion();
        var r = wrap.getBoundingClientRect();
        var w = wrap.offsetWidth || 140;
        var margin = window.innerWidth <= 600 ? 8 : 16;
        var toLeft = (r.left + w / 2) < window.innerWidth / 2;
        var c = clampPos(toLeft ? margin : (window.innerWidth - w - margin), r.top);
        snapSide = toLeft ? 'left' : 'right';
        wrap.classList.remove('tuck-left', 'tuck-right');
        wrap.classList.add(toLeft ? 'tuck-left' : 'tuck-right');
        wrap.classList.add('mascot-snapping');     // CSS handles the short left/top glide
        applyPos(c.left, c.top);
        savePos(c.left, c.top);
        motionTimer = setTimeout(function() {
            motionTimer = null;
            wrap.classList.remove('mascot-snapping');
            scheduleTuck();
        }, 360);
    };
    // Drag the figure off an edge and let go → hide, parking the reopen
    // handle where it left. The only hide-by-gesture.
    var dismissTo = function(side, y) {
        cancelMotion();
        snapSide = null; tucked = false;
        if (tuckTimer) { clearTimeout(tuckTimer); tuckTimer = null; }
        wrap.classList.remove('is-tucked', 'tuck-left', 'tuck-right', 'mascot-dragging', 'mascot-will-hide');
        setArt(currentMood, false);            // a normal face for the next reveal
        hide(side, y);                         // animated exit + reopen slides in
        try { localStorage.removeItem(POS_KEY); } catch (e) {}
    };
    // Double-tap sends it home to the default corner.
    var resetPos = function() {
        cancelMotion();
        var h = wrap.offsetHeight || 200;
        var defLeft = window.innerWidth <= 600 ? 8 : 16;
        if (tucked) setArt(currentMood, false);   // peek → real face before the glide home
        snapSide = null; tucked = false;
        if (tuckTimer) { clearTimeout(tuckTimer); tuckTimer = null; }
        wrap.classList.remove('is-tucked', 'tuck-left', 'tuck-right');
        wrap.classList.add('mascot-snapping');
        applyPos(defLeft, window.innerHeight - h);
        try { localStorage.removeItem(POS_KEY); } catch (e) {}
        setTimeout(function() {
            wrap.classList.remove('mascot-snapping');
            // hand back to CSS bottom-anchoring (same spot, now tracks bottom)
            wrap.style.left = ''; wrap.style.top = ''; wrap.style.bottom = '';
        }, 400);
        say(pick(HOME));
    };
    imgEl.style.touchAction = 'none';
    imgEl.style.cursor = 'grab';
    imgEl.addEventListener('pointerdown', function(e) {
        dragging = true; moved = false;
        // Grabbing cancels any snap/exit in flight: pin the figure where
        // it visually is, then drop the transition so the drag tracks the
        // pointer immediately (no jump to a target).
        if (motionTimer || wrap.style.transition) {
            cancelMotion();
            var rp = wrap.getBoundingClientRect();
            wrap.style.transition = '';
            wrap.style.transform = '';
            wrap.style.opacity = '';
            wrap.classList.remove('mascot-will-hide');
            applyPos(rp.left, rp.top);
        }
        wrap.classList.remove('mascot-snapping');
        var r = wrap.getBoundingClientRect();
        baseLeft = r.left; baseTop = r.top;
        sx = e.clientX; sy = e.clientY;
        imgEl.style.cursor = 'grabbing';
        try { imgEl.setPointerCapture(e.pointerId); } catch (er) {}
    });
    imgEl.addEventListener('pointermove', function(e) {
        if (!dragging) return;
        var dx = e.clientX - sx, dy = e.clientY - sy;
        // Only switch into drag mode once the pointer actually moves,
        // so a plain tap never re-anchors the figure or hides the bubble.
        if (!moved && Math.abs(dx) + Math.abs(dy) > 4) {
            moved = true;
            untuck();                       // come fully out to be dragged
            wrap.classList.add('mascot-dragging');
        }
        if (!moved) return;
        var c = dragClamp(baseLeft + dx, baseTop + dy);
        applyPos(c.left, c.top);
        // Cue "let go to hide" once ~40%+ is dragged off any edge.
        var w2 = wrap.offsetWidth || 140, h2 = wrap.offsetHeight || 200;
        var offFrac = Math.max(-c.left / w2, (c.left + w2 - window.innerWidth) / w2,
                               -c.top / h2, (c.top + h2 - window.innerHeight) / h2);
        wrap.classList.toggle('mascot-will-hide', offFrac > 0.4);
        // Flip bar/menu above↔below & left↔right live (pass the known
        // position so it doesn't force a layout read each move).
        updateBubbleSide(c.top, c.left + baseW() * mascotScale / 2);
    });
    var lastTap = 0, tapTimer = null;
    var endDrag = function(e) {
        if (!dragging) return;
        dragging = false;
        wrap.classList.remove('mascot-dragging');
        imgEl.style.cursor = 'grab';
        try { imgEl.releasePointerCapture(e.pointerId); } catch (er) {}
        if (moved) {
            wrap.classList.remove('mascot-will-hide');
            var rr = wrap.getBoundingClientRect();
            // Released with ~40%+ dragged past any edge → hide immediately,
            // handle parked where it left; otherwise snap to the edge.
            var offFrac = Math.max(-rr.left / rr.width, (rr.right - window.innerWidth) / rr.width,
                                   -rr.top / rr.height, (rr.bottom - window.innerHeight) / rr.height);
            if (offFrac > 0.4) {
                dismissTo((rr.left + rr.width / 2) < window.innerWidth / 2 ? 'left' : 'right',
                          rr.top + rr.height / 2);
            } else {
                snapToEdge();             // simple snap to nearest edge — no inertia
            }
            return;
        }
        // Tapping while tucked just peeks it out — no line.
        if (tucked) { untuck(); return; }
        // No movement — tell a single tap from a double tap.
        var now = Date.now();
        if (now - lastTap < 320) {
            lastTap = 0;
            if (tapTimer) { clearTimeout(tapTimer); tapTimer = null; }
            resetPos();
        } else {
            lastTap = now;
            if (tapTimer) clearTimeout(tapTimer);
            tapTimer = setTimeout(function() { sayMoods(CLICK_MOODS); tapTimer = null; }, 320);
        }
    };
    imgEl.addEventListener('pointerup', endDrag);
    imgEl.addEventListener('pointercancel', endDrag);
    window.addEventListener('resize', function() {
        applySize();
        if (wrap.style.left) { var c = clampPos(parseInt(wrap.style.left, 10), parseInt(wrap.style.top, 10)); applyPos(c.left, c.top); }
    });
    restorePos();

    var lastTheme = document.documentElement.getAttribute('data-theme');
    new MutationObserver(function() {
        var t = document.documentElement.getAttribute('data-theme');
        if (t !== lastTheme) { lastTheme = t; say(pick(t === 'dark' ? THEME.dark : THEME.light)); }
    }).observe(document.documentElement, { attributes: true, attributeFilter: ['data-theme'] });

    var nav = document.querySelector('nav.main-nav');
    if (nav) {
        var navCool = false;
        nav.addEventListener('mouseenter', function() {
            if (navCool || !ambient()) return;
            navCool = true;
            say(pick(NAV));
            setTimeout(function() { navCool = false; }, 30000);
        });
    }

    var mascotArticle = document.querySelector('.post-body.full-content');
    if (mascotArticle) {
        var halfShown = false, endShown = false, wentDeep = false, backCooling = false;
        var ticking = false;
        // Cache the article bottom (re-measured on size/resize) so the
        // scroll handler doesn't force a layout read every frame.
        var artBottom = 0;
        var measureArt = function() {
            artBottom = mascotArticle.getBoundingClientRect().bottom +
                (window.scrollY || document.documentElement.scrollTop);
        };
        measureArt();
        if ('ResizeObserver' in window) new ResizeObserver(measureArt).observe(mascotArticle);
        window.addEventListener('load', measureArt);
        window.addEventListener('resize', measureArt, { passive: true });
        var onArticleScroll = function() {
            ticking = false;
            var st = window.scrollY || document.documentElement.scrollTop;
            var target = Math.max(1, artBottom - window.innerHeight);
            var pct = Math.min(1, Math.max(0, st / target));
            if (!halfShown && pct > 0.45 && pct < 0.9) { halfShown = true; if (ambient()) say(pick(HALF)); }
            if (!endShown && pct > 0.97) { endShown = true; say(pick(END)); }
            if (pct > 0.5) wentDeep = true;
            // Scrolled back near the top after having gone deep.
            if (wentDeep && !backCooling && st < window.innerHeight * 0.25) {
                wentDeep = false; backCooling = true;
                if (ambient()) say(pick(BACKTOP));
                setTimeout(function() { backCooling = false; }, 30000);
            }
        };
        window.addEventListener('scroll', function() {
            if (!ticking) { requestAnimationFrame(onArticleScroll); ticking = true; }
        }, { passive: true });
    }

    // Been on the page a long while (regardless of activity).
    setTimeout(function() { if (ambient()) say(pick(LONGSTAY)); }, 240000);
    setTimeout(function() { if (ambient()) say(pick(LONGSTAY)); }, 540000);

    // Welcomed back when returning to the tab after a while away.
    var hiddenAt = 0, lastReturn = 0;
    document.addEventListener('visibilitychange', function() {
        if (document.hidden) {
            hiddenAt = Date.now();
        } else if (hiddenAt && Date.now() - hiddenAt > 8000 && Date.now() - lastReturn > 45000) {
            lastReturn = Date.now();
            say(pick(RETURN));
        }
    });

    // Park the reopen handle on the edge the figure left from, at that
    // height (clamped so the pill always stays fully on-screen).
    var REOPEN_KEY = 'mascotReopen';
    var placeReopen = function(side, y) {
        var w = reopen.offsetWidth || 46, h = reopen.offsetHeight || 46;
        reopen.classList.toggle('side-right', side === 'right');
        // Always position via `left` (right edge = innerWidth - w) so the
        // release snap can transition the left value on either side.
        reopen.style.left = (side === 'right' ? (window.innerWidth - w) : 0) + 'px';
        if (y == null) { reopen.style.top = ''; reopen.style.bottom = '16px'; return; }
        reopen.style.top = Math.max(8, Math.min(window.innerHeight - h - 8, y - h / 2)) + 'px';
        reopen.style.bottom = 'auto';
    };
    var dismissAnimTimer = null;
    // Hide with a quick fade+shrink exit while the reopen handle slides in
    // over it (reflow-committed, so the exit fires immediately). Pass
    // side/y to park the handle where the figure left; omit them (menu
    // Hide) to read its current spot. Remembered across visits.
    var hide = function(side, y) {
        if (side === undefined) {
            var r = wrap.getBoundingClientRect();
            side = (r.left + r.width / 2) < window.innerWidth / 2 ? 'left' : 'right';
            y = r.top + r.height / 2;
        }
        placeReopen(side, y);
        wrap.style.transition = 'none';
        wrap.style.transformOrigin = (side === 'right' ? 'right' : 'left') + ' bottom';
        void wrap.offsetWidth;                  // commit the start frame
        wrap.style.transition = 'opacity 0.2s var(--ease), transform 0.2s var(--ease-out)';
        wrap.style.opacity = '0';
        wrap.style.transform = 'scale(0.5)';
        reopen.classList.add('is-visible');     // handle slides in, overlapping the exit
        try { localStorage.setItem(HIDE_KEY, '1'); } catch (e) {}
        try { localStorage.setItem(REOPEN_KEY, JSON.stringify({ side: side, y: Math.round(y) })); } catch (e) {}
        if (dismissAnimTimer) clearTimeout(dismissAnimTimer);
        dismissAnimTimer = setTimeout(function() {
            dismissAnimTimer = null;
            wrap.classList.add('is-hidden');    // fully out
            wrap.style.transition = ''; wrap.style.transform = ''; wrap.style.opacity = '';
            wrap.style.transformOrigin = '';
            wrap.style.left = ''; wrap.style.top = ''; wrap.style.bottom = '';
        }, 210);
    };
    var show = function() {
        if (dismissAnimTimer) { clearTimeout(dismissAnimTimer); dismissAnimTimer = null; }
        ensureLoaded();
        // Clear any in-flight exit-animation styles before re-showing.
        wrap.style.transition = ''; wrap.style.transform = ''; wrap.style.opacity = '';
        wrap.style.transformOrigin = '';
        // Emerge right where the reopen handle sat — snapped to that edge
        // at that height — so the figure appears to step out from beside
        // the button, instead of jumping back to the default corner.
        var pos = null;
        try { pos = JSON.parse(localStorage.getItem(REOPEN_KEY)); } catch (e) {}
        if (pos && pos.side) {
            var w = wrap.offsetWidth || 140, h = wrap.offsetHeight || 200;
            var margin = window.innerWidth <= 600 ? 8 : 16;
            var left = pos.side === 'right' ? (window.innerWidth - w - margin) : margin;
            var c = clampPos(left, (pos.y || window.innerHeight / 2) - h / 2);
            applyPos(c.left, c.top);
            savePos(c.left, c.top);
            snapSide = pos.side;
            wrap.classList.remove('tuck-left', 'tuck-right');
            wrap.classList.add(pos.side === 'right' ? 'tuck-right' : 'tuck-left');
        }
        wrap.classList.remove('is-hidden');
        wrap.classList.add('is-ready');
        reopen.classList.remove('is-visible');
        try { localStorage.setItem(HIDE_KEY, '0'); } catch (e) {}
        try { localStorage.removeItem(REOPEN_KEY); } catch (e) {}
        if (snapSide) scheduleTuck();
    };
    // The reopen handle is draggable too: slide it up/down along an
    // edge (and across the midline to switch edges) to reposition it;
    // its spot is remembered. A plain tap (or keyboard) still summons.
    reopen.style.touchAction = 'none';
    var reDragging = false, reMoved = false, reSX = 0, reSY = 0,
        reBaseLeft = 0, reBaseTop = 0, reSwallowClick = false;
    reopen.addEventListener('pointerdown', function(e) {
        reDragging = true; reMoved = false; reSwallowClick = false;
        var r = reopen.getBoundingClientRect();
        reBaseLeft = r.left; reBaseTop = r.top; reSX = e.clientX; reSY = e.clientY;
        reopen.style.transition = 'none';   // follow the finger 1:1
        try { reopen.setPointerCapture(e.pointerId); } catch (er) {}
    });
    reopen.addEventListener('pointermove', function(e) {
        if (!reDragging) return;
        var dx = e.clientX - reSX, dy = e.clientY - reSY;
        if (!reMoved && Math.abs(dx) + Math.abs(dy) > 4) {
            reMoved = true;
            // Detach into a full, freely-moved disc (drops the edge clip).
            reopen.classList.add('is-grabbing');
            reopen.classList.remove('side-right');
        }
        if (!reMoved) return;
        var w = reopen.offsetWidth || 46, h = reopen.offsetHeight || 46;
        reopen.style.left = Math.max(4, Math.min(window.innerWidth - w - 4, reBaseLeft + dx)) + 'px';
        reopen.style.top  = Math.max(4, Math.min(window.innerHeight - h - 4, reBaseTop + dy)) + 'px';
        reopen.style.bottom = 'auto';
    });
    var reEnd = function(e) {
        if (!reDragging) return;
        reDragging = false;
        try { reopen.releasePointerCapture(e.pointerId); } catch (er) {}
        if (reMoved) {
            reSwallowClick = true;   // a drag isn't a summon
            var r = reopen.getBoundingClientRect();
            var side = (r.left + r.width / 2) < window.innerWidth / 2 ? 'left' : 'right';
            var y = r.top + r.height / 2;
            // FLIP: pin the released (disc) position with no transition and
            // force a reflow to commit it as the start frame, THEN turn the
            // snap transition on and set the edge target — so the snap
            // animation fires immediately on release, every time.
            reopen.style.transition = 'none';
            reopen.style.left = r.left + 'px';
            reopen.style.top = r.top + 'px';
            reopen.style.bottom = 'auto';
            void reopen.offsetWidth;                 // commit the start frame
            reopen.style.transition = 'left 0.18s var(--ease-out), top 0.18s var(--ease-out), ' +
                                      'border-radius 0.18s var(--ease-out), box-shadow 0.18s var(--ease)';
            reopen.classList.remove('is-grabbing');  // disc → edge tab (morphs)
            placeReopen(side, y);                    // → glides home to the edge
            try { localStorage.setItem(REOPEN_KEY, JSON.stringify({ side: side, y: Math.round(y) })); } catch (er) {}
            setTimeout(function() { reopen.style.transition = ''; }, 240);
        } else {
            reopen.style.transition = '';
        }
    };
    reopen.addEventListener('pointerup', reEnd);
    reopen.addEventListener('pointercancel', reEnd);
    reopen.addEventListener('click', function(e) {
        if (reSwallowClick) { reSwallowClick = false; e.preventDefault(); e.stopPropagation(); return; }
        show(); greet();
    });

    // Settings popover — pick a chatter level, or hide the mascot.
    var LEVEL_MSG = {
        full: { mood: 'excited', zh: '活泼模式~ 我会多陪你聊聊！',     en: 'Lively mode~ I’ll chat with you more!' },
        less: { mood: 'happy',   zh: '少话模式，只在关键时刻冒头。',   en: 'Quiet mode — I’ll pipe up only at key moments.' },
        mute: { mood: 'shy',     zh: '静音啦，我安安静静待着就好。',   en: 'Muted — I’ll just sit here quietly.' }
    };
    var gear = wrap.querySelector('.mascot-settings');
    var menu = wrap.querySelector('.mascot-menu');
    var levelBtns = menu.querySelectorAll('button[data-level]');
    var syncMenu = function() {
        levelBtns.forEach(function(btn) {
            btn.setAttribute('aria-pressed', btn.getAttribute('data-level') === chatLevel ? 'true' : 'false');
        });
    };
    syncMenu();
    // Size slider — preview with a GPU transform while dragging (the
    // container box stays fixed, so the menu doesn't shift under the
    // thumb), then commit the real width on release.
    var sizeSlider = menu.querySelector('.mascot-size');
    sizeSlider.value = mascotScale;
    var committedScale = mascotScale;
    var sizeRaf = false;
    sizeSlider.addEventListener('input', function() {
        wrap.classList.add('mascot-resizing');
        if (sizeRaf) return;
        sizeRaf = true;
        requestAnimationFrame(function() {
            sizeRaf = false;
            imgEl.style.transform = 'scale(' + (parseFloat(sizeSlider.value) / committedScale).toFixed(3) + ')';
        });
    });
    var commitSize = function() {
        mascotScale = parseFloat(sizeSlider.value);
        committedScale = mascotScale;
        imgEl.style.transform = '';
        wrap.classList.remove('mascot-resizing');
        applySize();
        try { localStorage.setItem(SIZE_KEY, mascotScale); } catch (e) {}
    };
    sizeSlider.addEventListener('change', commitSize);
    // Pop the menu out right beside the SETTINGS BAR: to the bar's right
    // when it's on the left half of the screen, to its left when on the
    // right half. Top-aligned with the bar and clamped so it never runs
    // off-screen. The side class drives the slide-out animation; offsets
    // are inline and wrap-relative.
    var positionMenu = function() {
        var wr = wrap.getBoundingClientRect();
        var gr = gear.getBoundingClientRect();   // the settings bar
        var mw = menu.offsetWidth || 180, mh = menu.offsetHeight || 240;
        var vw = window.innerWidth, vh = window.innerHeight, gap = 8;
        var onLeftHalf = (gr.left + gr.width / 2) < vw / 2;
        var vx = onLeftHalf ? (gr.right + gap) : (gr.left - gap - mw);
        vx = Math.min(Math.max(gap, vx), vw - mw - gap);
        var vy = Math.min(Math.max(gap, gr.top), vh - mh - gap);
        menu.classList.remove('side-left', 'side-right');
        menu.classList.add(onLeftHalf ? 'side-right' : 'side-left');
        menu.style.left = (vx - wr.left) + 'px';
        menu.style.top = (vy - wr.top) + 'px';
        menu.style.right = 'auto';
        menu.style.bottom = 'auto';
        menu.style.margin = '0';
    };
    var menuOpen = function(open) {
        if (open) positionMenu();
        menu.classList.toggle('is-open', open);
        gear.classList.toggle('is-active', open);
        gear.setAttribute('aria-expanded', open ? 'true' : 'false');
    };
    window.addEventListener('resize', function() {
        if (menu.classList.contains('is-open')) positionMenu();
    }, { passive: true });
    gear.addEventListener('click', function(e) {
        e.stopPropagation();
        menuOpen(!menu.classList.contains('is-open'));
    });
    menu.addEventListener('click', function(e) {
        e.stopPropagation();
        var btn = e.target.closest('button');
        if (!btn) return;
        if (btn.getAttribute('data-act') === 'hide') { menuOpen(false); hide(); return; }
        var lvl = btn.getAttribute('data-level');
        if (lvl) {
            chatLevel = lvl;
            try { localStorage.setItem(CHAT_KEY, chatLevel); } catch (er) {}
            syncMenu();
            menuOpen(false);
            say(LEVEL_MSG[chatLevel], 3200, true);   // force, so the mute notice still shows
        }
    });
    // Close the menu on any outside interaction, or on Escape.
    document.addEventListener('click', function() { menuOpen(false); });
    document.addEventListener('keydown', function(e) {
        if (e.key === 'Escape' && menu.classList.contains('is-open')) { menuOpen(false); gear.focus(); }
    });

    ['click', 'keydown', 'scroll'].forEach(function(ev) {
        window.addEventListener(ev, resetIdle, { passive: true });
    });

    // Boot — respect a remembered "hidden" choice; otherwise greet.
    var dismissed = false;
    try { dismissed = localStorage.getItem(HIDE_KEY) === '1'; } catch (e) {}
    if (dismissed) {
        wrap.classList.add('is-hidden');
        try {
            var rp0 = JSON.parse(localStorage.getItem(REOPEN_KEY));
            if (rp0 && rp0.side) placeReopen(rp0.side, rp0.y);
        } catch (e) {}
        reopen.classList.add('is-visible');
    } else {
        setTimeout(function() {
            ensureLoaded(); wrap.classList.add('is-ready'); greet();
            // On phones, after the greeting, rest tucked at the left
            // edge so the figure never covers the article text.
            if (window.innerWidth <= 600 && !snapSide) {
                snapSide = 'left';
                wrap.classList.add('tuck-left');
                scheduleTuck();
            }
        }, 1200);
    }
})();

// ── 404 mascot — random "lost" expression + playful line ───────
// The static markup ships a sensible default; this just freshens it
// so each visit feels a little alive.
(function() {
    var el = document.getElementById('error-404');
    if (!el) return;
    var BASE = 'https://cdn.jsdelivr.net/gh/rinuuan/blog-assets@main/mascot/chibi';
    var moods = ['confused', 'surprised', 'sad', 'shy'];
    var lines = [
        { zh: '诶？这一页…被你翻丢啦！',   en: 'Uh-oh — this page ran off!' },
        { zh: '唔…这里空空的，什么都没有哦。', en: 'Umm… it’s empty here, nothing to see.' },
        { zh: '你是不是…悄悄迷路了呀？',   en: 'Are you… secretly a little lost?' },
        { zh: '这页被我藏起来咯——才怪！', en: 'I hid this page — just kidding!' },
        { zh: '翻了半天，连我都没找着。',   en: 'I looked everywhere — even I can’t find it.' }
    ];
    var mood = moods[Math.floor(Math.random() * moods.length)];
    var line = lines[Math.floor(Math.random() * lines.length)];
    var img = el.querySelector('.error-mascot');
    if (img) {
        var pre = new Image();
        pre.onload = function() { img.src = pre.src; };
        pre.src = BASE + '/' + mood + '.png';
    }
    var zh = el.querySelector('.error-bubble .lang-zh');
    var en = el.querySelector('.error-bubble .lang-en');
    if (zh) zh.textContent = line.zh;
    if (en) en.textContent = line.en;
})();
//

body.script:
//
// Bound on DOMContentLoaded, not load: the theme / language / variant
// toggles only need their (static) buttons in the DOM, so there's no
// reason to wait for every image and font to finish — waiting on `load`
// left the toggles dead for seconds on image-heavy articles. (The
// comment-form lifecycle further down still uses `load`, since it must
// wait for Blogger's own comment script.)
document.addEventListener("DOMContentLoaded", () => {
  const root = document.documentElement;

  // Update copyright year
  const yearEl = document.getElementById("current-year");
  if (yearEl) yearEl.textContent = new Date().getFullYear();

  // UI transition effect — cache targets once to avoid re-querying on every toggle
  const fadeTargets = document.querySelectorAll('.site-header, nav.main-nav, #main-content, .site-footer, .top-actions');
  const triggerContentFade = callback => {
      fadeTargets.forEach(el => el.classList.add('content-fade-out'));
      setTimeout(() => {
          callback();
          setTimeout(() => fadeTargets.forEach(el => el.classList.remove('content-fade-out')), 50);
      }, 350);
  };

  // Theme toggle logic. Body's own transition handles the color fade;
  // buttons / tags / etc. pick up the variable change via their own
  // transition rules.
  const themeToggle = document.getElementById("theme-toggle");
  if (themeToggle) {
    themeToggle.addEventListener("click", () => {
      const newTheme = root.getAttribute("data-theme") === "dark" ? "light" : "dark";
      root.setAttribute("data-theme", newTheme);
      localStorage.setItem("theme", newTheme);
    });
  }

  // Language toggle logic
  const langToggle = document.getElementById("lang-toggle");
  if (langToggle) {
    langToggle.addEventListener("click", () => {
      triggerContentFade(() => {
          const newLang = root.getAttribute("data-lang") === "zh" ? "en" : "zh";
          root.setAttribute("data-lang", newLang);
          localStorage.setItem("lang", newLang);
      });
    });
  }

  // Text nodes walk helper
  const ignoreTags = new Set(["SCRIPT", "STYLE", "NOSCRIPT", "IFRAME", "CODE"]);
  const walkTextNodes = (node, applyConversion) => {
    const walker = document.createTreeWalker(node, NodeFilter.SHOW_TEXT, {
      acceptNode: n => ignoreTags.has(n.parentNode.nodeName) ? NodeFilter.FILTER_REJECT : NodeFilter.FILTER_ACCEPT
    }, false);

    let currentNode;
    while (currentNode = walker.nextNode()) {
        if (currentNode.nodeValue.trim()) currentNode.nodeValue = applyConversion(currentNode.nodeValue);
    }
  };

  // Simplified/Traditional conversion
  const loadOpenCC = (targetVariant, callback) => {
    const executeConversion = () => {
        const converter = window.OpenCC.Converter({
            from: targetVariant === "simp" ? "tw" : "cn",
            to: targetVariant === "simp" ? "cn" : "tw"
        });
        walkTextNodes(document.body, converter);
        root.setAttribute("data-variant", targetVariant);
        localStorage.setItem("variant", targetVariant);
        if (callback) callback();
    };

    if (window.OpenCC) {
      executeConversion();
    } else {
      const script = document.createElement("script");
      script.src = "https://cdn.jsdelivr.net/npm/opencc-js@1.0.5/dist/umd/full.js";
      script.async = true;
      script.defer = true;
      script.onload = executeConversion;
      document.head.appendChild(script);
    }
  };

  // Expose for infinite scroll: convert a freshly-added subtree to the
  // current variant. Only Traditional needs work (Simplified is the stored
  // form); best-effort — skips silently if OpenCC isn't loaded yet.
  let s2tConv = null;
  window.__rinuanToVariant = subtree => {
    if (!subtree || root.getAttribute("data-variant") !== "trad" || !window.OpenCC) return;
    try {
      if (!s2tConv) s2tConv = window.OpenCC.Converter({ from: "cn", to: "tw" });
      walkTextNodes(subtree, s2tConv);
    } catch (e) {}
  };

  // Initialize variant
  if (root.getAttribute("data-variant") === "trad") {
    setTimeout(() => loadOpenCC("trad"), 200);
  }

  const variantToggle = document.getElementById("variant-toggle");
  if (variantToggle) {
    variantToggle.addEventListener("click", () => {
      triggerContentFade(() => loadOpenCC(root.getAttribute("data-variant") === "simp" ? "trad" : "simp"));
    });
  }
});
//

//
window.addEventListener("DOMContentLoaded", () => {

  // ── Post-process pass — applied to initial page and reusable for
  // newly loaded posts (infinite scroll). Operates on any root.
  const isFullPostView = !!document.querySelector('.post-body.full-content');

  function adjustPostTypography(root) {
      root.querySelectorAll('.post-outer').forEach(post => {
          const body = post.querySelector('.post-body');
          if (!body) return;

          const tagNodes = post.querySelectorAll('.post-tag, .hidden-tag');
          const tags = Array.from(tagNodes).map(t => {
              const raw = t.getAttribute('data-raw-tag') || t.textContent;
              return raw.trim().toLowerCase();
          });

          const isEnglish = tags.includes('english') || tags.includes('en');
          if (isEnglish) {
              // Style writes are batched via cssText to avoid multiple
              // style invalidations per post
              body.style.cssText += 'line-height:1.7;text-align:left;hyphens:auto;-webkit-hyphens:auto;word-spacing:0.05em;';
              body.setAttribute('lang', 'en');
          } else {
              body.style.cssText += 'line-height:2.2;text-align:justify;hyphens:none;-webkit-hyphens:none;word-spacing:normal;';
              body.setAttribute('lang', 'zh-Hans');
          }

          // Mirror the lang attribute onto the title so the CSS :lang()
          // rule can pick the right word-break behaviour for CJK vs Latin
          const title = post.querySelector('.post-title');
          if (title) title.setAttribute('lang', isEnglish ? 'en' : 'zh-Hans');

          // Add native lazy-loading + async decoding to article images
          // (Blogger doesn't emit these by default on user-uploaded images)
          body.querySelectorAll('img').forEach((img, idx) => {
              if (!img.hasAttribute('loading')) {
                  // First image on a single-post view is likely above the fold → eager
                  img.setAttribute('loading', idx === 0 && isFullPostView ? 'eager' : 'lazy');
              }
              if (!img.hasAttribute('decoding')) img.setAttribute('decoding', 'async');
          });
      });
  }

  adjustPostTypography(document);

  // Static translation dictionary — the sole source of tag translations.
  // No external translation API is called. Unknown tags fall through to
  // their original text (Chinese stays Chinese, English stays English).
  // To add a new tag, just append a pair here.
  const navDictionary = {
      // Navigation
      "Home": { zh: "首页", en: "Home" },
      "首页": { zh: "首页", en: "Home" },
      "首頁": { zh: "首页", en: "Home" },

      // Currently used labels on the blog
      "English": { zh: "英文", en: "English" },
      "中文": { zh: "中文", en: "Chinese" },
      "Novels": { zh: "小说", en: "Novels" },
      "小说": { zh: "小说", en: "Novels" },
      "Poems": { zh: "诗歌", en: "Poems" },
      "诗歌": { zh: "诗歌", en: "Poems" },
      "Prose": { zh: "散文", en: "Prose" },
      "散文": { zh: "散文", en: "Prose" },
      "第七层": { zh: "第七层", en: "7th Floor" },
      "7th Floor": { zh: "第七层", en: "7th Floor" },

      // Common categories — ready when you start using them
      "Life": { zh: "生活", en: "Life" },
      "生活": { zh: "生活", en: "Life" },
      "Tech": { zh: "科技", en: "Tech" },
      "科技": { zh: "科技", en: "Tech" },
      "技术": { zh: "技术", en: "Tech" },
      "Art": { zh: "艺术", en: "Art" },
      "艺术": { zh: "艺术", en: "Art" },

      // Writing & literature
      "Fiction": { zh: "小说", en: "Fiction" },
      "Poetry": { zh: "诗歌", en: "Poetry" },
      "Essay": { zh: "散文", en: "Essay" },
      "Essays": { zh: "散文", en: "Essays" },
      "随笔": { zh: "随笔", en: "Musings" },
      "笔记": { zh: "笔记", en: "Notes" },
      "Notes": { zh: "笔记", en: "Notes" },
      "日记": { zh: "日记", en: "Diary" },
      "Diary": { zh: "日记", en: "Diary" },
      "翻译": { zh: "翻译", en: "Translation" },
      "Translation": { zh: "翻译", en: "Translation" },
      "书评": { zh: "书评", en: "Book Reviews" },
      "读书": { zh: "读书", en: "Reading" },
      "Reading": { zh: "读书", en: "Reading" },
      "Reviews": { zh: "评论", en: "Reviews" },
      "评论": { zh: "评论", en: "Reviews" },

      // Hobbies & culture
      "摄影": { zh: "摄影", en: "Photography" },
      "Photography": { zh: "摄影", en: "Photography" },
      "旅行": { zh: "旅行", en: "Travel" },
      "Travel": { zh: "旅行", en: "Travel" },
      "美食": { zh: "美食", en: "Food" },
      "Food": { zh: "美食", en: "Food" },
      "音乐": { zh: "音乐", en: "Music" },
      "Music": { zh: "音乐", en: "Music" },
      "电影": { zh: "电影", en: "Films" },
      "Film": { zh: "电影", en: "Films" },
      "Movies": { zh: "电影", en: "Movies" },

      // Tech & thought
      "编程": { zh: "编程", en: "Programming" },
      "Programming": { zh: "编程", en: "Programming" },
      "Code": { zh: "代码", en: "Code" },
      "设计": { zh: "设计", en: "Design" },
      "Design": { zh: "设计", en: "Design" },
      "AI": { zh: "AI", en: "AI" },
      "教程": { zh: "教程", en: "Tutorials" },
      "Tutorial": { zh: "教程", en: "Tutorial" },
      "思考": { zh: "思考", en: "Thoughts" },
      "Thoughts": { zh: "思考", en: "Thoughts" },
      "随想": { zh: "随想", en: "Reflections" }
  };

  // Look up a tag in the dictionary. Unknown tags fall through to their
  // original text — Chinese tags keep Chinese in both modes, English
  // tags keep English in both modes. This is intentional: a broken
  // translation is worse than no translation.
  function getTranslations(rawTag) {
      return navDictionary[rawTag] || { zh: rawTag, en: rawTag };
  }

  // Apply translations to tags within `root`. Synchronous — no network,
  // no localStorage, resolves immediately. Safe to call repeatedly
  // (idempotent: writing the same translation twice is a no-op).
  function translateTagsIn(root) {
      root.querySelectorAll('.translatable-tag').forEach(link => {
          const rawTag = link.getAttribute('data-raw-tag');
          if (!rawTag) return;
          const trans = getTranslations(rawTag);
          const zhSpan = link.querySelector('.lang-zh');
          const enSpan = link.querySelector('.lang-en');
          if (zhSpan) zhSpan.textContent = trans.zh;
          if (enSpan) enSpan.textContent = trans.en;
      });
  }

  translateTagsIn(document);

  // Expose a combined post-processor for the infinite-scroll IIFE.
  // It wraps both passes (typography + tag translation) so newly
  // appended posts get the same treatment as the initial page.
  window.__rinuanPostProcess = function(root) {
      adjustPostTypography(root);
      translateTagsIn(root);
  };

  // ── Infinite scroll ────────────────────────────────────────────────
  // Multi-post views only (home / label / archive / search). Fetches the
  // server's own next ("older") page and appends its posts — page 2+
  // render the correct count even though Blogger's buggy first page may
  // show a single post, so this fills the list AND keeps markup identical.
  // Replaces the classic pager; dedupes against posts already shown.
  (function() {
      // Skip single posts / static pages: they also render a .blog-pager
      // (prev/next-POST nav), so without this guard we'd append other
      // posts' full bodies into the article. Only multi-post lists (which
      // show snippets, never a full-content body) should paginate.
      if (document.querySelector('.post-body.full-content')) return;
      const list = document.querySelector('.blog-posts');
      const pager = document.querySelector('.blog-pager');
      const firstOlder = pager && pager.querySelector('a.older-link');
      if (!list || !firstOlder) return;   // last page → nothing to load

      let nextUrl = firstOlder.getAttribute('href');
      let loading = false, ended = false;
      pager.style.display = 'none';

      const keyOf = post => {
          const a = post.querySelector('h2.post-title a, a.read-more');
          return a ? (a.getAttribute('href') || '') : '';
      };
      const seen = {};
      list.querySelectorAll('.post-outer').forEach(p => { const k = keyOf(p); if (k) seen[k] = 1; });

      const L = (zh, en) => '<span class="lang-zh">' + zh + '</span><span class="lang-en">' + en + '</span>';
      const sentinel = document.createElement('div');
      sentinel.className = 'infinite-sentinel';
      const status = document.createElement('div');
      status.className = 'infinite-status';
      list.after(sentinel, status);

      const setStatus = html => { status.innerHTML = html; status.classList.add('is-visible'); };
      const showEnd = () => setStatus('<span class="end-dingbat">···</span>');
      const showError = () => {
          setStatus(L('加载出错', 'Couldn’t load') + '<button type="button" class="retry-btn">' + L('重试', 'Retry') + '</button>');
          status.querySelector('.retry-btn').addEventListener('click', () => { status.classList.remove('is-visible'); load(); });
      };

      const load = () => {
          if (loading || ended || !nextUrl) return;
          loading = true;
          setStatus('<span class="loading-dot"></span>');
          fetch(nextUrl, { credentials: 'same-origin' })
              .then(r => { if (!r.ok) throw 0; return r.text(); })
              .then(html => {
                  const doc = new DOMParser().parseFromString(html, 'text/html');
                  const tmp = document.createElement('div');
                  doc.querySelectorAll('.blog-posts .post-outer').forEach(p => {
                      const k = keyOf(p);
                      if (k && seen[k]) return;          // skip a post already on the page
                      if (k) seen[k] = 1;
                      tmp.appendChild(document.importNode(p, true));
                  });
                  if (window.__rinuanPostProcess) window.__rinuanPostProcess(tmp);
                  if (window.__rinuanToVariant) window.__rinuanToVariant(tmp);   // Simplified→Traditional in Traditional mode
                  while (tmp.firstChild) list.appendChild(tmp.firstChild);
                  const older = doc.querySelector('.blog-pager a.older-link');
                  nextUrl = older ? older.getAttribute('href') : null;
                  loading = false;
                  if (nextUrl) status.classList.remove('is-visible'); else { ended = true; showEnd(); }
              })
              .catch(() => { loading = false; showError(); });
      };

      if ('IntersectionObserver' in window) {
          new IntersectionObserver(entries => { if (entries[0].isIntersecting) load(); },
              { rootMargin: '600px 0px' }).observe(sentinel);
      } else {
          pager.style.display = '';   // no observer → fall back to the classic pager
          sentinel.remove(); status.remove();
      }
  })();
});
//

b:if.script:
//
// ====================================================================
// Comment module — encapsulated IIFE.
// Handles every aspect of the customized Blogger comment experience:
//   1. i18n strings for buttons (CN-simp / CN-trad / EN)
//   2. Form lifecycle: lazy iframe init, expand/collapse, reply mode
//   3. DOM restructuring: hi-res avatars, localized delete buttons,
//      reply folding (YouTube-style), tree branch visuals
//   4. Bootstrap: MutationObserver wiring
// All scoped here. Nothing leaks to global scope.
// ====================================================================
(function() {
    'use strict';

    // ── 1. i18n strings ──────────────────────────────────────────────
    const TEXT_REPLY    = '<span class="lang-zh"><span class="variant-simp">回复</span><span class="variant-trad">回覆</span></span><span class="lang-en">Reply</span>';
    const TEXT_CANCEL   = '<span class="lang-zh"><span class="variant-simp">取消回复</span><span class="variant-trad">取消回覆</span></span><span class="lang-en">Cancel</span>';
    const TEXT_WRITE    = '<span class="lang-zh"><span class="variant-simp">写留言</span><span class="variant-trad">寫留言</span></span><span class="lang-en">Write a comment</span>';
    const TEXT_COLLAPSE = '<span class="lang-zh"><span class="variant-simp">收起留言框</span><span class="variant-trad">收起留言框</span></span><span class="lang-en">Collapse comment box</span>';
    const TEXT_DELETE   = '<span class="lang-zh"><span class="variant-simp">删除</span><span class="variant-trad">刪除</span></span><span class="lang-en">Delete</span>';

    // ── 2. Form lifecycle ────────────────────────────────────────────
    // Encapsulates the Blogger comment iframe in our own .form-inner
    // wrapper so we can apply RTL trick + color filters. Single iframe
    // is reused for both the top-level form and inline reply forms,
    // moved around via DOM relocation.

    function initFormLifecycle() {
        const commentToggleBtn = document.getElementById("comment-toggle");
        const commentsWrapper = document.querySelector(".comments-wrapper");
        const customFormContainer = document.getElementById("custom-comment-form-container");

        if (!commentsWrapper || !customFormContainer) return;

        // One-shot iframe initializer. Returns true once iframe is wrapped.
        function initializeCommentIframe() {
            const editorIframe = document.getElementById("comment-editor");
            if (!editorIframe) return false;
            const formInner = document.createElement('div');
            formInner.className = 'form-inner';
            formInner.appendChild(editorIframe);
            customFormContainer.appendChild(formInner);
            commentsWrapper.classList.add("show-main-form");
            customFormContainer.classList.add("is-expanded");
            if (commentToggleBtn) commentToggleBtn.innerHTML = TEXT_COLLAPSE;
            return true;
        }

        // Try immediate init; otherwise watch DOM for iframe arrival.
        // 8s safety timeout disconnects observer if iframe never shows
        // (e.g. comments disabled on this post).
        if (!initializeCommentIframe()) {
            const iframeObserver = new MutationObserver(() => {
                if (initializeCommentIframe()) iframeObserver.disconnect();
            });
            iframeObserver.observe(commentsWrapper, { childList: true, subtree: true });
            setTimeout(() => iframeObserver.disconnect(), 8000);
        }

        // Toggle button: write ↔ collapse
        if (commentToggleBtn) {
            commentToggleBtn.addEventListener("click", e => {
                e.preventDefault();
                const editorIframe = document.getElementById("comment-editor");
                const isExpanded = commentsWrapper.classList.contains("show-main-form");

                // Reset any active inline reply buttons
                document.querySelectorAll(".comment-reply.cancel-active").forEach(btn => {
                    btn.classList.remove("cancel-active");
                    btn.innerHTML = TEXT_REPLY;
                });

                if (isExpanded) {
                    commentsWrapper.classList.remove("show-main-form");
                    commentToggleBtn.innerHTML = TEXT_WRITE;
                    customFormContainer.classList.remove("is-expanded");
                } else {
                    // Returning from a reply context to the main form.
                    // The container may currently sit under some
                    // comment's .item-control AND still be expanded.
                    // Teleporting it back to the top would skip the
                    // collapse animation entirely. So: collapse first,
                    // relocate when the collapse settles, then expand
                    // in the new position to play the open animation.
                    const mainComments = document.getElementById("comments");
                    const formInner = customFormContainer.querySelector('.form-inner');
                    const srcLink = document.getElementById("comment-editor-src");
                    const wasExpanded = customFormContainer.classList.contains("is-expanded");
                    const alreadyAtTop = customFormContainer.parentNode === commentsWrapper &&
                                         customFormContainer.nextSibling === mainComments;

                    const relocateAndExpand = () => {
                        if (mainComments && !alreadyAtTop) {
                            commentsWrapper.insertBefore(customFormContainer, mainComments);
                        }
                        if (editorIframe && formInner && !formInner.contains(editorIframe)) {
                            formInner.appendChild(editorIframe);
                        }
                        if (srcLink && editorIframe && editorIframe.src !== srcLink.href) {
                            editorIframe.src = srcLink.href;
                        }
                        commentsWrapper.classList.add("show-main-form");
                        commentToggleBtn.innerHTML = TEXT_COLLAPSE;
                        void customFormContainer.offsetWidth;  // force reflow
                        customFormContainer.classList.add("is-expanded");
                    };

                    if (wasExpanded && !alreadyAtTop) {
                        // Phase 1: collapse where it currently sits.
                        customFormContainer.classList.remove("is-expanded");
                        // Phase 2: wait for collapse to finish, then
                        // relocate + re-expand. 320ms matches the
                        // 0.3s grid-template-rows transition + tiny
                        // safety buffer. transitionend would be more
                        // precise but fires for every transitioned
                        // property (grid-rows AND opacity AND margin),
                        // adding event-cleanup complexity for no gain.
                        setTimeout(relocateAndExpand, 320);
                    } else {
                        relocateAndExpand();
                    }
                }
            });
        }

        // Inline reply button delegation. Clicking a reply button on
        // an existing comment relocates the shared iframe under that
        // comment, switching the form into "reply mode". Clicking
        // again (now showing "Cancel") returns the form to the top.
        document.body.addEventListener("click", e => {
            const replyBtn = e.target.closest(".comment-reply");
            if (!replyBtn) return;

            const isCancel = replyBtn.classList.contains("cancel-active");
            const iframe = document.getElementById("comment-editor");
            const formInner = customFormContainer.querySelector('.form-inner');

            // Snap-hide iframe during relocation to avoid flicker
            if (iframe) { iframe.style.transition = 'none'; iframe.style.opacity = '0'; }
            if (customFormContainer) {
                customFormContainer.style.transition = 'none';
                customFormContainer.classList.remove("is-expanded");
            }

            setTimeout(() => {
                // Clear any other active reply buttons
                document.querySelectorAll(".comment-reply.cancel-active").forEach(btn => {
                    if (btn !== replyBtn) {
                        btn.classList.remove("cancel-active");
                        btn.innerHTML = TEXT_REPLY;
                    }
                });

                if (isCancel) {
                    // Cancel reply → return form to top
                    replyBtn.classList.remove("cancel-active");
                    replyBtn.innerHTML = TEXT_REPLY;
                    const mainComments = document.getElementById("comments");
                    if (mainComments && formInner && iframe) {
                        formInner.appendChild(iframe);
                        commentsWrapper.insertBefore(customFormContainer, mainComments);
                        const srcLink = document.getElementById("comment-editor-src");
                        if (srcLink) iframe.src = srcLink.href;
                    }
                    commentsWrapper.classList.add("show-main-form");
                    if (commentToggleBtn) commentToggleBtn.innerHTML = TEXT_COLLAPSE;
                } else {
                    // Start reply → move form directly under this
                    // comment's action row (.item-control). Using
                    // insertAdjacentElement('afterend', ...) keeps
                    // the form as a sibling of the actions, NOT a
                    // descendant of .comment — important because
                    // .comment may contain nested replies, and
                    // appending to .comment would push the form
                    // below those replies.
                    replyBtn.classList.add("cancel-active");
                    replyBtn.innerHTML = TEXT_CANCEL;
                    commentsWrapper.classList.remove("show-main-form");
                    if (commentToggleBtn) commentToggleBtn.innerHTML = TEXT_WRITE;

                    const itemControl = replyBtn.closest(".item-control");
                    if (itemControl && formInner && iframe) {
                        itemControl.insertAdjacentElement('afterend', customFormContainer);
                        formInner.appendChild(iframe);
                    }
                }

                // Two-stage restoration (matches the original behavior):
                // First un-hide the container so its expand animation
                // can play; only fade the iframe back in once the
                // container has settled, otherwise the iframe blinks
                // visible inside a still-collapsing container.
                if (customFormContainer) {
                    void customFormContainer.offsetWidth;  // force reflow
                    customFormContainer.style.transition = '';
                    customFormContainer.classList.add("is-expanded");
                }
                if (iframe) {
                    setTimeout(() => {
                        iframe.style.transition = 'opacity 0.4s ease';
                        iframe.style.opacity = '1';
                    }, 50);
                }
            }, 20);
        });
    }

    // ── 3. Comment restructuring (DOM observer) ──────────────────────
    // Blogger's threadedComments injects comment markup asynchronously
    // and unpredictably. We watch the comment container for mutations
    // and run idempotent restructuring passes whenever it changes.

    let restructureTimer;

    function restructureComments() {
        // Avatars → 2x retina. Blogger ships at s35; replies need
        // 48px (24px slot), top-level need 80px (40px slot).
        document.querySelectorAll(".avatar-image-container img:not([data-hires])").forEach(img => {
            const src = img.getAttribute("src");
            if (!src) return;
            const isReply = !!img.closest(".comment-replies");
            const target = isReply ? "s48-c" : "s80-c";
            const updated = src
                .replace(/\/s\d+(-c)?\//, "/" + target + "/")
                .replace(/=s\d+(-c)?(?=$|[&?])/, "=" + target);
            if (updated !== src) img.setAttribute("src", updated);
            img.dataset.hires = "true";
        });

        // Localize native English "Delete" buttons
        document.querySelectorAll(".item-control a:not([data-cleaned-del])").forEach(btn => {
            const lowerText = btn.innerText.trim().toLowerCase();
            if (lowerText === "delete" || lowerText === "删除") {
                btn.innerHTML = TEXT_DELETE;
                btn.dataset.cleanedDel = "true";
            }
        });

        // Clean up duplicated reply buttons, normalize single reply per comment
        document.querySelectorAll(".comment:not([data-cleaned])").forEach(comment => {
            const controls = comment.querySelector(".item-control");
            const replyBtns = comment.querySelectorAll(".comment-reply");
            if (controls && replyBtns.length) {
                controls.appendChild(replyBtns[0]);
                replyBtns[0].style.display = "inline-flex";
                replyBtns[0].innerHTML = replyBtns[0].classList.contains("cancel-active") ? TEXT_CANCEL : TEXT_REPLY;
                for (let i = 1; i < replyBtns.length; i++) replyBtns[i].remove();
                comment.dataset.cleaned = "true";
            }
        });

        // YouTube-style reply folding. Wrap reply list in a grid that
        // animates open/closed via grid-template-rows transition.
        document.querySelectorAll(".comment-replies:not([data-folded])").forEach(thread => {
            const ol = thread.querySelector("ol");
            const nestedComments = thread.querySelectorAll(".comment");
            if (!ol || nestedComments.length === 0) return;

            const parentComment = thread.closest('.comment');

            // Add vertical trunk line connecting parent → replies
            if (parentComment && !parentComment.querySelector(':scope > .thread-trunk')) {
                const trunk = document.createElement('div');
                trunk.className = 'thread-trunk';
                parentComment.insertBefore(trunk, parentComment.firstChild);
            }

            // Wrap the OL in a 2-level container so we can animate
            // grid-template-rows: 0fr ↔ 1fr smoothly
            const wrapper = document.createElement("div");
            wrapper.className = "replies-grid-wrapper";
            const inner = document.createElement("div");
            inner.className = "replies-grid-inner";
            ol.parentNode.insertBefore(wrapper, ol);
            wrapper.appendChild(inner);
            inner.appendChild(ol);

            // Build the "N replies" toggle button
            const toggleBtn = document.createElement("button");
            const hiddenCount = nestedComments.length;
            toggleBtn.className = "reply-toggle-btn";
            toggleBtn.dataset.count = hiddenCount;

            const buildLabel = isExpanded => {
                const arrowSvg = '<svg viewBox="0 0 24 24"><path d="M7 10l5 5 5-5z"/></svg>';
                if (isExpanded) {
                    return arrowSvg +
                        '<span class="lang-zh"><span class="variant-simp">收起回复</span><span class="variant-trad">收起回覆</span></span>' +
                        '<span class="lang-en">Collapse replies</span>';
                }
                const enText = hiddenCount === 1 ? 'reply' : 'replies';
                return arrowSvg +
                    '<span class="lang-zh"><span class="variant-simp">' + hiddenCount + ' 条回复</span><span class="variant-trad">' + hiddenCount + ' 則回覆</span></span>' +
                    '<span class="lang-en">' + hiddenCount + ' ' + enText + '</span>';
            };

            toggleBtn.innerHTML = buildLabel(false);
            toggleBtn.onclick = e => {
                e.preventDefault();
                const isExpanded = toggleBtn.classList.contains("expanded");
                wrapper.classList.toggle("is-expanded", !isExpanded);
                toggleBtn.classList.toggle("expanded");
                toggleBtn.innerHTML = buildLabel(!isExpanded);
            };

            // Insert toggle button right after the wrapper
            if (wrapper.nextSibling) {
                wrapper.parentNode.insertBefore(toggleBtn, wrapper.nextSibling);
            } else {
                wrapper.parentNode.appendChild(toggleBtn);
            }

            thread.dataset.folded = "true";
        });

        // Add tree-branch visual element to each reply comment
        document.querySelectorAll(".comment-replies .comment:not([data-branched])").forEach(childComment => {
            const branch = document.createElement('div');
            branch.className = 'yt-branch';
            childComment.insertBefore(branch, childComment.firstChild);
            childComment.dataset.branched = "true";
        });

        // Strip Blogger's native "Load more..." links
        const wrapper = document.querySelector(".comments-wrapper");
        if (wrapper) {
            wrapper.querySelectorAll("a, span").forEach(el => {
                const lowerText = el.innerText.trim().toLowerCase();
                if (lowerText === "load more..." || lowerText.includes("load more")) el.remove();
            });
        }
    }

    // ── 4. Bootstrap ─────────────────────────────────────────────────
    // Debounce coalesces Blogger's burst of micro-mutations (it fires
    // dozens of childList events when injecting or re-rendering a
    // comment thread). 16ms = one frame — short enough to never be
    // perceived as a flash, long enough to batch a single user
    // action's worth of mutations into one restructure pass.
    const commentObserver = new MutationObserver(() => {
        clearTimeout(restructureTimer);
        restructureTimer = setTimeout(restructureComments, 16);
    });

    function startObserving() {
        const container = document.getElementById("comments") || document.querySelector(".comments-wrapper");
        if (container) commentObserver.observe(container, { childList: true, subtree: true });
    }

    // Form lifecycle is bound on "load" (waits for Blogger script).
    // Observer starts on "DOMContentLoaded" to catch the first batch
    // of comments even if they're already in the initial HTML.
    if (document.readyState === 'loading') {
        document.addEventListener('DOMContentLoaded', startObserving);
    } else {
        startObserving();
    }
    window.addEventListener("load", initFormLifecycle);
})();
//
